insert into public.questions
  (id, ruleset, topic, tier, scenario, options, correct_index, explanation, status)
values
  ('obr-001', 'obr', 'Balks', 'district', 'R1, one out. The pitcher comes set, begins his delivery toward the plate, then freezes halfway through and steps off.', '["Balk — award R1 second base","No pitch, no penalty","Ball on the batter","Time is called; warn the pitcher"]'::jsonb, 0, 'Once the pitcher starts his motion to pitch, he must deliver the ball without interruption. Stopping partway through is a balk with a runner on, and R1 is awarded second.', 'published'),
  ('obr-002', 'obr', 'Balks', 'district', 'R2, nobody out. From the set, the pitcher steps directly toward second base and fakes a throw without stepping off the rubber.', '["Balk — a pitcher may never feint while on the rubber","Legal — a feint to second is allowed with a proper step","Balk — he must disengage before any feint","Illegal pitch — ball on the batter"]'::jsonb, 1, 'Second base is the one base a pitcher may feint a throw to while engaged, as long as he steps toward it. Feinting to first or third from the rubber is a balk.', 'published'),
  ('obr-003', 'obr', 'Balks', 'provincial', 'R1. A right-hander in the set position lifts his free leg, and it swings past the back edge of the pitching rubber before he spins and throws to first for a pickoff attempt.', '["Legal pickoff — the runner is out if tagged","Balk — once the leg breaks the plane of the rubber he is committed to pitch","Legal only if the throw beats the runner","No call — the leg position is irrelevant from the set"]'::jsonb, 1, 'When the free foot swings past the back edge of the rubber, the pitcher must deliver to the plate (or throw to second on a runner advancing there). Spinning back to first from that position is a balk.', 'published'),
  ('obr-004', 'obr', 'Balks', 'district', 'R1 and R3. The batter is still settling into the box, head down, when the pitcher hurries into his delivery and pitches.', '["Legal — the batter must be ready at all times","No pitch — start over with a warning","Quick pitch: a balk — both runners advance one base","Quick pitch: ball on the batter, runners hold"]'::jsonb, 2, 'A pitch thrown before the batter is reasonably set is a quick pitch. With runners on base it is a balk; with the bases empty it is called a ball.', 'published'),
  ('obr-005', 'obr', 'Balks', 'provincial', 'R1 and R3, one out. From the rubber the pitcher steps toward third and fakes a throw, then immediately wheels and throws to first, still engaged, catching R1 off the base.', '["Legal — he stepped toward each base he threw to","Out if the tag is applied before R1 returns","Balk — the third-to-first move is illegal","Legal only if R3 was breaking for home"]'::jsonb, 2, 'Feinting a throw to third from the rubber is itself a balk under current rules, so the popular old "fake third, throw first" move is dead. Both runners are awarded a base.', 'published'),
  ('obr-006', 'obr', 'Balks', 'district', 'R2. The pitcher comes to the set position but delivers to the plate in one continuous motion without ever pausing.', '["Legal — a pause is only required with two strikes","Balk — he must come to a complete stop before delivering","Ball on the batter","Legal — the stop is optional from the windup"]'::jsonb, 1, 'From the set position the pitcher must come to a complete and discernible stop with runners on base. Rolling through the set without stopping is a balk.', 'published'),
  ('obr-007', 'obr', 'Balks', 'district', 'R1. While standing on the rubber taking his sign, the ball slips out of the pitcher’s hand and rolls a metre in front of the mound.', '["No pitch — retrieve the ball and resume","Ball on the batter","Balk — R1 is awarded second","Dead ball; do-over with a warning"]'::jsonb, 2, 'A pitcher who drops the ball while touching the rubber has balked when runners are on base. With the bases empty it is a ball only if the ball crosses a foul line.', 'published'),
  ('obr-008', 'obr', 'Balks', 'district', 'Bases empty. The pitcher delivers before the batter has both feet set and his eyes on the pitcher.', '["Ball on the batter — quick pitch with nobody on","Balk","Strike if it is in the zone","No call — bases are empty"]'::jsonb, 0, 'A quick pitch is always illegal. With the bases empty the penalty is a ball added to the count; with runners on it becomes a balk.', 'published'),
  ('obr-009', 'obr', 'Balks', 'provincial', 'R2 only, first base open. Without stepping off, the pitcher suddenly throws to the first baseman standing near his bag. No runner is advancing toward first.', '["Legal — he may throw to any base","Balk — throw to an unoccupied base with no play on","Legal if the first baseman was holding his position","Time — no pitch"]'::jsonb, 1, 'While engaged, a pitcher may only throw to an unoccupied base to make a play on an advancing runner. Throwing to an empty base for no reason is a balk.', 'published'),
  ('obr-010', 'obr', 'Balks', 'provincial', 'R1. While standing on the rubber, the pitcher brings his pitching hand to his mouth, then grips the ball without wiping off.', '["Balk — R1 advances","Ball on the batter — not a balk","Ejection for doctoring the ball","No penalty unless he throws a pitch"]'::jsonb, 1, 'Going to the mouth while engaged (without wiping) is penalized with a ball on the batter, not a balk. It is a common trap answer — the balk penalties are listed separately.', 'published'),
  ('obr-011', 'obr', 'Interference', 'district', 'Bunt in front of the plate. The batter-runner runs the last 20 feet to first entirely in fair territory, inside the running lane, and the catcher’s throw hits him in the back.', '["Interference — batter-runner out, ball dead","No call — the throw hit him accidentally","Obstruction on the catcher","Interference only if he slowed down"]'::jsonb, 0, 'On the last half to first base the batter-runner must be inside the 3-foot running lane (which is in foul ground). Being hit by a quality throw while outside the lane in fair territory is interference: he is out and other runners return.', 'published'),
  ('obr-012', 'obr', 'Interference', 'provincial', 'R1, one out. On a ground ball to short, R1 slides well wide of second base, never able to reach the bag with hand or foot, and takes out the pivot man as the relay to first sails wide.', '["Only R1 is out — the throw was wide anyway","R1 and the batter-runner are both out","No call — hard slides are part of the game","The batter-runner returns to first"]'::jsonb, 1, 'A slide that is not a bona fide attempt to reach the base, made to break up a double play, is interference: the sliding runner is out and so is the batter-runner. The wide throw does not matter.', 'published'),
  ('obr-013', 'obr', 'Interference', 'district', 'R2, nobody out. A ground ball up the middle strikes R2 on the shin in fair territory before it reaches the shortstop positioned behind the baseline.', '["Live ball — play on","Dead ball — R2 out, batter awarded first base","Dead ball — both R2 and the batter are out","Dead ball — R2 returns to second, batter bats again"]'::jsonb, 1, 'A runner struck by a fair batted ball before it passes an infielder is out, and the ball is dead. The batter is awarded first base and credited with a hit.', 'published'),
  ('obr-014', 'obr', 'Interference', 'provincial', 'R1 holding at first with the first baseman playing in front of him. A sharp grounder gets past the first baseman untouched and then hits R1. No other infielder had a chance to make a play on the ball.', '["R1 is out — a runner hit by a fair ball is always out","Live ball — no interference, play on","Dead ball — batter awarded first, R1 stays","R1 is out only if the ball was catchable"]'::jsonb, 1, 'Once a fair ball passes an infielder (other than the pitcher) and no other infielder has a play, a runner hit by it is not out. The ball stays live.', 'published'),
  ('obr-015', 'obr', 'Interference', 'provincial', 'R2. The catcher’s mitt nicks the bat during the swing, but the batter still lines a clean single and R2 scores.', '["Catcher’s interference — batter must take first, R2 returns to third","The play stands — the interference is disregarded since everyone advanced","Dead ball immediately when the mitt touches the bat","The manager may choose the result of the play or the award"]'::jsonb, 1, 'When catcher’s interference occurs but the batter reaches first and every runner advances at least one base, the interference is ignored and the play stands automatically. The manager’s option only exists when the play turned out worse than the award.', 'published'),
  ('obr-016', 'obr', 'Interference', 'district', 'R2 rounding third on a base hit. The third-base coach grabs the runner’s arm and physically pulls him back toward the bag as the throw comes in.', '["Legal coaching","The runner is out for coach’s interference","Delayed dead ball — award decided after the play","Warning to the coach, runner returns to third"]'::jsonb, 1, 'A coach who physically assists a runner — grabbing, pushing, or pulling him — causes that runner to be called out. Verbal direction is fine; touching is not.', 'published'),
  ('obr-017', 'obr', 'Interference', 'district', 'R1 stealing on the pitch. The batter swings and misses for strike three, then shifts his feet and blocks the catcher’s throwing lane to second. The throw is never made.', '["Only the batter is out — strike three","The batter is out on strikes and R1 is also out for the interference","R1 returns to first, batter out","No call — the batter may stand anywhere in the box"]'::jsonb, 1, 'A just-retired batter who hinders the catcher’s play on a runner commits interference, and the runner being played on is called out as well. Two outs on the play.', 'published'),
  ('obr-018', 'obr', 'Interference', 'provincial', 'Deep fly down the line. A spectator reaches clearly over the outfield fence into the field of play and deflects the ball just as the right fielder camps under it at the warning track.', '["Home run — the ball left the playing field","Dead ball — the batter is declared out for spectator interference","Do-over pitch","Ground-rule double automatically"]'::jsonb, 1, 'When a spectator reaches into the field and prevents what the umpire judges would have been a catch, the batter is out. Otherwise the umpire places all runners where they would have ended up absent the interference.', 'published'),
  ('obr-019', 'obr', 'Interference', 'provincial', 'R2 stealing third. The batter swings and misses, and his natural follow-through clips the catcher’s mitt as the catcher comes up to throw. The throw dies and R2 is safe.', '["The batter is out for interference","Dead ball — strike on the batter, R2 returns to second","Play stands — follow-through contact is nothing","R2 is out for the batter’s interference"]'::jsonb, 1, 'Unintentional backswing contact is not full interference: the ball is dead, the swing counts as a strike, and runners return. Nobody is out unless that strike was strike three.', 'published'),
  ('obr-020', 'obr', 'Interference', 'provincial', 'R1 stealing. The plate umpire is clipped by the catcher’s arm as the catcher throws, the throw arrives late, and R1 slides in safely.', '["R1 returns to first — umpire interference","The play stands — R1 is safe","R1 is automatically out","The pitch is replayed"]'::jsonb, 0, 'When the plate umpire hinders the catcher’s throw and the runner is not retired, the ball is dead and the runner returns. If the throw had retired the runner, the out would stand.', 'published'),
  ('obr-021', 'obr', 'Obstruction', 'district', 'R1 is caught in a rundown between first and second. Retreating, he collides with the first baseman, who is standing in the basepath without the ball waiting for a throw.', '["Dead ball immediately — R1 is awarded second base","Delayed dead ball — see how the play ends","R1 is out for leaving the basepath","No call — incidental contact"]'::jsonb, 0, 'Obstruction of a runner who is being played on kills the play immediately, and the runner is awarded at least one base beyond the last one he legally touched — here, second.', 'published'),
  ('obr-022', 'obr', 'Obstruction', 'district', 'Base hit to right. Rounding first, the batter-runner has to swerve around the first baseman, who is standing in the path watching the outfield with no ball coming. The runner stops at first.', '["Dead ball — award second base automatically","Delayed dead ball — award second only if the umpire judges the hindrance cost him the base","No call — the runner chose to stop","Warn the fielder; no award possible"]'::jsonb, 1, 'Obstruction with no play being made on the runner is a delayed dead ball. The umpire lets the play finish and then awards whatever bases nullify the obstruction — which may be none if it cost the runner nothing.', 'published'),
  ('obr-023', 'obr', 'Obstruction', 'district', 'Slow roller to the third baseman, who charges and is about to glove the ball when R2, advancing, runs into him.', '["Obstruction — R2 is awarded third","Nothing — a train wreck, play on","The fielder had right of way; R2 risks an interference call, not obstruction","Both players are penalized"]'::jsonb, 2, 'A fielder in the act of fielding a batted ball is protected; he cannot be guilty of obstruction. It is the runner who must avoid him, and contact that hinders the fielder is offensive interference.', 'published'),
  ('obr-024', 'obr', 'Obstruction', 'district', 'R1 rounds second on a ball in the gap. The shortstop, nowhere near the ball, drops to a knee and mimics taking a throw and applying a tag, and R1 slides.', '["Legal deke","Obstruction — the fake tag hindered the runner","Interference on the shortstop","No call unless contact occurs"]'::jsonb, 1, 'A fake tag is obstruction: faking a play without the ball hinders the runner even without contact. The umpire protects the runner and awards bases that nullify the act; many leagues also treat it as an ejectable unsportsmanlike act.', 'published'),
  ('obr-025', 'obr', 'Obstruction', 'provincial', 'R2 tries to score on a single. The catcher, without the ball, plants himself on the plate and blocks the sliding runner’s leg; the throw then arrives and the tag is applied.', '["Out — the throw beat him","Obstruction — the run scores","Out if the block was unintentional","Runner returns to third"]'::jsonb, 1, 'A fielder without possession may not block a base or the plate. Blocking the runner before having the ball is obstruction on a runner being played on: dead ball, and the runner is awarded home.', 'published'),
  ('obr-026', 'obr', 'Obstruction', 'provincial', 'Swinging bunt. As the batter-runner breaks from the box, the catcher chasing the ball shoves him off stride before fielding it, then throws him out at first by half a step.', '["Out stands — the contact was before the throw","Obstruction before reaching first — dead ball, batter-runner awarded first","Offsetting: interference and obstruction cancel","Do-over pitch"]'::jsonb, 1, 'A batter-runner obstructed before touching first while the defense is playing on him gets first base; the ball is dead. (If the catcher had been in the act of fielding the ball, he would have been protected instead.)', 'published'),
  ('obr-027', 'obr', 'Obstruction', 'provincial', 'Hit into the corner, no play on the runner. R2 is bumped by the shortstop while rounding second; the umpire signals delayed obstruction and judges it cost him third base at most. R2 keeps running and is thrown out by five metres trying to score.', '["Safe — obstruction protects him all the way home","Out stands — he advanced beyond his protection at his own risk","Out is nullified and he returns to third","Dead ball when the obstruction occurred"]'::jsonb, 1, 'Obstruction protection with no play on only reaches the base the umpire judges the hindrance cost — here, third. A runner who keeps going past his protected base advances at his own risk, so the out at the plate stands.', 'published'),
  ('obr-028', 'obr', 'Obstruction', 'provincial', 'Pickoff at first. The first baseman straddles the bag in the runner’s dive path before the throw arrives; R1, diving back, is blocked from the base and tagged.', '["Out — good baseball play","Obstruction — a fielder cannot block the base before he has the ball","No call — the runner left the base voluntarily","Balk on the pitcher"]'::jsonb, 1, 'Until he possesses the ball, a fielder may not deny the runner access to the base. Blocking the dive-back lane before the throw arrives is obstruction, and the runner is protected back to first (or awarded beyond it if a play was being made on him — here he is safe at first at minimum).', 'published'),
  ('obr-029', 'obr', 'Force & tag plays', 'district', 'R1, one out. Ground ball to the first baseman, who steps on first and then throws to second, where the shortstop stretches and touches the bag well before R1 arrives — but applies no tag.', '["Double play — inning-style force at second","R1 is safe — the force was removed when the batter was put out first","R1 is out if the throw beat him by more than a step","Dead ball — runners return"]'::jsonb, 1, 'Putting out the batter-runner at first removes the force on R1. At second it becomes a tag play: touching the bag is no longer enough — R1 must be tagged while off base.', 'published'),
  ('obr-030', 'obr', 'Force & tag plays', 'district', 'R2 only, nobody out. Ground ball to the shortstop, who runs over and stomps on second base as R2 slides in, never tagging him.', '["Out — force play at second","Safe — R2 was never forced, so he must be tagged","Out if the fielder beat him to the bag","Safe only if he overslides"]'::jsonb, 1, 'A force exists only when a runner must vacate his base for the batter-runner. R2 with first base empty is not forced; retiring him requires a tag.', 'published'),
  ('obr-031', 'obr', 'Force & tag plays', 'district', 'Bases loaded, two out. Ground ball to third; the third baseman steps on the bag for the force on R2 just after R3 crosses the plate.', '["Run counts — R3 scored before the out","Run does not count — no run can score when the third out is a force","Run counts if the play at third was close","Umpire’s judgment on the timing"]'::jsonb, 1, 'Timing is irrelevant when the third out is a force out (or the batter-runner out before first): the run can never score.', 'published'),
  ('obr-032', 'obr', 'Force & tag plays', 'district', 'R3, two out. The batter hits a slow chopper and is thrown out at first, an eyelash after R3 touches home plate.', '["Run counts — he crossed before the out","Run does not count — the batter-runner was out before reaching first","Run counts because it was not a force at first","Protest situation"]'::jsonb, 1, 'The batter-runner being retired before touching first is one of the automatic run-killers, exactly like a force: no run may score on the play regardless of timing.', 'published'),
  ('obr-033', 'obr', 'Force & tag plays', 'district', 'Rundown between third and home. The catcher, ball in his bare hand, dives and touches the runner with only his empty glove.', '["Out — any touch with glove or hand counts","Safe — the tag must be made with the ball or the glove holding the ball","Out if the runner was off the baseline","Safe only if the runner avoids the sweep"]'::jsonb, 1, 'A legal tag is contact with the ball itself, or with the hand or glove actually holding the ball. Touching a runner with an empty glove while the ball is in the other hand retires no one.', 'published'),
  ('obr-034', 'obr', 'Force & tag plays', 'provincial', 'Force at second. The ball lodges in the webbing of the shortstop’s glove, so he pulls the glove off and stretches it out, glove-with-ball touching the bag before the runner arrives.', '["Out — the ball touched the base first","Out — the glove still counts as part of the fielder","Safe — a detached glove holding the ball is not secure possession by the fielder","Dead ball — lodged ball, everyone advances one base"]'::jsonb, 2, 'For a force out, the fielder must touch the base while securely holding the ball in his hand or a worn glove. A glove that is no longer on his hand touching the bag does not record the out.', 'published'),
  ('obr-035', 'obr', 'Force & tag plays', 'provincial', 'Bases loaded, two out. R1 beats the force at second, touching the bag, but his momentum slides him past it. He is tagged while off the base — after R3 had already crossed the plate.', '["No run — third out on a force at second","Run scores — the force was satisfied when he touched the bag, so it became a time play","No run — an overslide is treated as never reaching the base","Run scores only if the defence does not appeal"]'::jsonb, 1, 'Touching the base extinguishes the force even if the runner slides past it. The tag afterward is an ordinary third out, so the run counts if it crossed before the tag — a classic time play.', 'published'),
  ('obr-036', 'obr', 'Force & tag plays', 'district', 'R2 and R3, two out. Single to left. R3 scores easily; R2 is tagged out sliding into third just after R3 touched the plate.', '["No run — the inning ended on the out","Run counts — the third out was a tag play made after the run crossed","No run — R2’s out is treated like a force","Run counts only with fewer than two outs"]'::jsonb, 1, 'A tag of a runner who is not forced is a time play. Since R3 touched home before the tag at third, the run counts. Umpires should watch the plate touch and the tag in the same look.', 'published'),
  ('obr-037', 'obr', 'Force & tag plays', 'provincial', 'Play at the plate. The catcher fields the throw up the line, and the runner, with a clear lane to slide to the plate, lowers his shoulder and runs him over, jarring the ball loose.', '["Safe — the ball came out","Out — a runner who deviates to initiate avoidable contact violates the collision rule, and the ball is dead","Safe, but the runner is ejected","Do-over — both players were at fault"]'::jsonb, 1, 'A runner may not deviate from his path to initiate contact with the catcher when a slide was available. He is out even though the ball came loose, the ball is dead, and the contact can also draw an ejection.', 'published'),
  ('obr-038', 'obr', 'Batted ball rulings', 'district', 'Deep drive down the left-field line strikes the foul pole above the top of the fence.', '["Foul ball","Home run","Ground-rule double","Umpire’s discretion"]'::jsonb, 1, 'The foul pole is in fair territory — the name is misleading. A fly ball that hits the pole above the fence is a home run.', 'published'),
  ('obr-039', 'obr', 'Batted ball rulings', 'district', 'A hard grounder hits the first-base bag and ricochets into foul territory, where it is picked up behind the base.', '["Foul — it ended up in foul ground","Fair — a ball that touches a base is fair","Dead ball — replay the pitch","Foul unless a fielder could have played it"]'::jsonb, 1, 'First and third base sit entirely in fair territory. The instant a batted ball touches a bag it is fair, no matter where it bounces afterward.', 'published'),
  ('obr-040', 'obr', 'Batted ball rulings', 'district', 'A bunt wobbles up the third-base line and comes to rest untouched exactly on the chalk, halfway between home and third.', '["Foul ball","Fair ball — the line is fair territory","No call until a fielder touches it","Dead ball"]'::jsonb, 1, 'The foul lines themselves are fair. A ball resting on any part of the line between home and the base is a fair ball.', 'published'),
  ('obr-041', 'obr', 'Batted ball rulings', 'district', 'A sinking fly ball lands untouched three feet beyond first base, in foul ground, then spins across the line into fair territory.', '["Fair — it ended up fair","Foul — past the base, the call is made where the ball first lands","Fair if a fielder could have caught it","Depends where it stops rolling"]'::jsonb, 1, 'Beyond first or third base, fair/foul is fixed by where the ball first touches the ground (or a fielder). Before the base it is judged where it is touched or comes to rest — a distinction worth drilling.', 'published'),
  ('obr-042', 'obr', 'Batted ball rulings', 'district', 'R1 and R2, nobody out. High pop-up to the shortstop; the umpire declares “infield fly, batter’s out.” The ball drops untouched at the shortstop’s feet, and R2 sprints to third and beats the late throw.', '["R2 must return — runners cannot advance on an infield fly","Batter is out; R2’s advance stands since he advanced at his own risk on a live ball","Batter is not out because the ball was dropped","Dead ball — both runners return"]'::jsonb, 1, 'The infield fly call retires the batter and removes the force, but the ball stays live. Runners may advance at their own risk whether or not the ball is caught.', 'published'),
  ('obr-043', 'obr', 'Batted ball rulings', 'provincial', 'R1, nobody out, no infield fly situation. The second baseman lets an easy soft line drive hit his glove and deliberately drops it, then starts a 6-4-3-style double play.', '["Legal — heads-up play","Dead ball — the batter is out for the intentional drop and R1 returns to first","Only the force at second stands","Umpire cannot judge intent"]'::jsonb, 1, 'An infielder who intentionally drops a fair fly or line drive with a force in effect kills the cheap double play: the ball is dead, the batter is out, and runners return. Letting it fall untouched, by contrast, is legal.', 'published'),
  ('obr-044', 'obr', 'Batted ball rulings', 'provincial', 'A comebacker glances off the pitcher’s leg while over fair territory, then rolls across the line and is picked up in foul ground before reaching first base.', '["Foul — it was in foul ground when touched by the fielder who picked it up","Fair — it was touched by a fielder while over fair territory","Foul — it never reached the base","Dead ball off the pitcher"]'::jsonb, 1, 'A batted ball touched by a fielder while over fair territory is a fair ball from that moment. Everything after the deflection — including rolling foul — is irrelevant.', 'published'),
  ('obr-045', 'obr', 'Batted ball rulings', 'district', 'A chopped ball bounces straight down onto home plate and then high into fair territory, where the catcher barehands it and throws the batter out.', '["Foul — the plate is foul territory","Dead ball — hitting the plate is a do-over","The out stands — home plate is fair territory","The batter cannot be out on a ball that hits the plate"]'::jsonb, 2, 'Home plate is just another piece of fair ground. A batted ball that strikes it is treated like any other batted ball — here, a fair ball and a routine out.', 'published'),
  ('obr-046', 'obr', 'Batted ball rulings', 'provincial', 'The batter lays down a bunt and drops his bat in fair territory as he runs. The slowly rolling ball bumps into the stationary bat; the umpire sees no intent.', '["Batter out — the ball touched his bat a second time","Foul ball automatically","Live ball — play on, the fair/foul call proceeds normally","Dead ball, runners return"]'::jsonb, 2, 'A fair ball rolling into a bat lying on the ground is nothing, provided the batter did not drop the bat onto the ball or intend to interfere. Judge intent; absent it, play on.', 'published'),
  ('obr-047', 'obr', 'Appeals', 'district', 'R1 sprints first-to-third on a base hit but never touches second. After time is back in, the pitcher steps off and throws to the shortstop, who tags second and tells the umpire the runner missed it.', '["Safe — the play is over once he reaches third","Out on appeal at second","The runner just returns to second","Appeals require the plate umpire’s permission first"]'::jsonb, 1, 'A missed base is an appeal play: with a live ball, before the next pitch or play, the defence tags the missed base (or the runner) and makes the claim unmistakably. The runner is out.', 'published'),
  ('obr-048', 'obr', 'Appeals', 'district', 'The batter rips a ball into the corner and cruises into third, but the first-base umpire sees him miss first by a foot. The defence appeals properly at first base.', '["He returns to first and the triple becomes a single","The batter-runner is out; the triple is wiped out","He keeps third — you cannot appeal first base","He is out only if he also missed second"]'::jsonb, 1, 'A proper appeal at a missed base retires the runner outright — it does not send him back. The apparent triple becomes an out at first.', 'published'),
  ('obr-049', 'obr', 'Appeals', 'district', 'R2, one out. Deep fly to centre, caught. R2 tags and makes third easily, but the defence believes he left early. The pitcher steps off and throws to the shortstop, who touches second base and states the claim clearly.', '["Nothing — you cannot appeal a tag-up","If the umpire judges R2 left before the catch, he is out on appeal","R2 simply returns to second","The appeal had to be made before R2 reached third"]'::jsonb, 1, 'Leaving too soon on a caught fly is appealable exactly like a missed base: live ball, unmistakable appeal at the base left early, before the next pitch or play.', 'published'),
  ('obr-050', 'obr', 'Appeals', 'provincial', 'Two out, R3. The batter singles and R3 scores, but the batter-runner misses first and the defence appeals at first before the next pitch.', '["Run scores — it crossed before the appeal","Run is nullified — the appeal out is the batter-runner failing to reach first","Run scores because an appeal is not a play","Defence must choose the out or the run"]'::jsonb, 1, 'An appeal for missing first is treated as the batter-runner being out before touching first — one of the outs that kills every run on the play, regardless of timing.', 'published'),
  ('obr-051', 'obr', 'Appeals', 'provincial', 'One out, R1 and R3. On a caught line drive, R1 is doubled off first for the third out — while R3, who left early, crosses the plate before that throw arrives. The defence then also appeals R3’s early departure at third.', '["Run counts — the inning was already over","The \"fourth-out\" appeal is upheld and the run is taken off the board","You cannot appeal after the third out","Run counts because R3 crossed before the third out"]'::jsonb, 1, 'The defence may appeal a fourth out, and if it is against a runner who scored, that out replaces the third out and cancels the run. It must be made before the infielders leave fair territory.', 'published'),
  ('obr-052', 'obr', 'Appeals', 'provincial', 'Inning-ending catch; R2 had left second well before the ball was caught. The whole infield jogs across the foul line toward the dugout, then the third baseman runs back out and asks for an appeal at second.', '["Valid — no pitch has intervened","Too late — the right to appeal ended when the infield left fair territory","Valid if made before the other team bats","The umpire may allow it at his discretion"]'::jsonb, 1, 'Appeal rights on a half-inning’s last play expire when the pitcher and all infielders have left fair territory. Once they cross the line, the appeal window is closed.', 'published'),
  ('obr-053', 'obr', 'Appeals', 'district', 'Two strikes. The batter checks his swing and the plate umpire calls the pitch a ball. The catcher immediately asks the plate umpire to check with the base umpire.', '["The plate umpire may refuse the request","The plate umpire must ask the base umpire, whose ruling then stands","Checked swings cannot be appealed with two strikes","Only the manager may request the appeal"]'::jsonb, 1, 'On a checked swing called a ball, the plate umpire is required to seek the base umpire’s judgment when the catcher (or manager) asks. The base umpire’s answer is final.', 'published'),
  ('obr-054', 'obr', 'Appeals', 'district', 'Close play at the plate — the runner’s hook slide misses home entirely and the tag misses him. The runner pops up and walks toward his dugout; the catcher follows and tags him a few steps away.', '["Safe — the play at the plate was over","Out — he never touched home and was tagged before returning","The run counts unless the defence appeals to the umpire verbally","Dead ball — he must be sent back to touch the plate"]'::jsonb, 1, 'A runner who misses home may correct the miss until he is tagged or the plate itself is tagged after he heads for the bench. The umpire makes no signal until one side resolves it — here, the tag retires him.', 'published'),
  ('obr-055', 'obr', 'Substitutions & lineups', 'district', 'A pinch hitter bats in the sixth and is then replaced in the seventh. In the ninth, the manager tries to send the same player back in to play second base.', '["Legal — position players may re-enter once","Illegal — a substitute who has been removed may not return in the same game","Legal only in extra innings","Legal if the opposing manager consents"]'::jsonb, 1, 'Under OBR-based rules, any player removed from the game is done for that game. (Some youth categories add re-entry privileges by local rule — know your tournament — but the baseline rule is no return.)', 'published'),
  ('obr-056', 'obr', 'Substitutions & lineups', 'district', 'A new left fielder trots out without anyone informing the plate umpire. He catches a fly ball two pitches later, and the offence protests the catch was made by an illegal player.', '["The catch is nullified","The substitute became legal the moment play resumed with him in the game — the catch stands","The substitute is ejected","The offence chooses whether the play stands"]'::jsonb, 1, 'Failing to announce a substitution has no penalty. An unannounced substitute becomes legal as soon as the ball is put in play with him participating. The catch stands.', 'published'),
  ('obr-057', 'obr', 'Substitutions & lineups', 'provincial', 'The number-five hitter bats in the number-four spot by mistake and doubles. Before a pitch is thrown to the next batter, the defensive manager points out the mistake to the plate umpire.', '["The double stands and the order just continues","The proper batter (the four hitter) is declared out and the double is wiped out","The improper batter (the five hitter) is declared out","Both batters are out"]'::jsonb, 1, 'On a timely batting-out-of-turn appeal, it is the batter who failed to bat — the proper batter — who is called out, and the improper batter’s action is nullified. The order resumes after the proper batter’s spot.', 'published'),
  ('obr-058', 'obr', 'Substitutions & lineups', 'provincial', 'Same mix-up: the five hitter bats out of turn and doubles — but this time the defence says nothing until after a pitch is thrown to the following batter.', '["The proper batter is out once the defence finally appeals","Too late — the improper batter is legalized, his double stands, and the order continues from his spot","The double is cancelled but no one is out","The game reverts to the correct spot with no other consequence"]'::jsonb, 1, 'One pitch to the next batter legalizes everything the improper batter did. The lineup then simply continues from the batter after the legalized one — which is why the offence sometimes skips a hitter unnoticed.', 'published'),
  ('obr-059', 'obr', 'Substitutions & lineups', 'district', 'Mid at-bat with a 2-1 count, the offensive manager sends up a pinch hitter for the injured batter.', '["Not allowed — substitutions only between at-bats","The pinch hitter takes over with the 2-1 count","The count resets to 0-0","The at-bat is ruled an out due to injury"]'::jsonb, 1, 'A batter may be replaced at any time the ball is dead, and the substitute inherits the existing count. Only with two strikes and a strikeout completed by the sub does the original batter get charged.', 'published'),
  ('obr-060', 'obr', 'Substitutions & lineups', 'district', 'A reliever is brought in, completes his warm-up pitches, and the manager immediately signals for another pitcher before the batter steps in.', '["Fine — pitching changes are unlimited","Not allowed — the reliever must pitch to at least one batter until that batter is put out or reaches base","Allowed if the reliever claims injury only after examination by the umpire","Allowed, but the team forfeits a mound visit"]'::jsonb, 1, 'A relief pitcher must face at least one batter to completion (injury or illness excepted, in the umpire’s judgment). The manager cannot swap him out before that.', 'published'),
  ('ll-001', 'll', 'Leaving early', 'majors', 'Majors game, R1. As the pitcher’s arm comes forward, R1 breaks for second. The batter takes the pitch for a ball, and R1 slides into second ahead of the catcher’s throw.', '["Stolen base — he beat the throw","R1 is out for leaving early","No out, but R1 is returned to first — he left before the ball reached the batter","Delayed dead ball — offence’s choice"]'::jsonb, 2, 'In Majors and below, runners may not leave the base until the pitched ball reaches the batter. Leaving early is not an out — the violation is remedied after the play, and a runner who advanced on it is sent back.', 'published'),
  ('ll-002', 'll', 'Leaving early', 'intermediate', 'Intermediate (50/70) game, R1. As the pitcher comes set, R1 walks two steps off first base into a lead.', '["Violation — runners may never lead off in Little League","Legal — leadoffs are allowed in Intermediate and above","Legal only after the first pitch of the at-bat","R1 must return once the pitcher looks at him"]'::jsonb, 1, 'The no-leadoff restriction belongs to Majors and below. From Intermediate (50/70) up, runners may lead off and steal exactly as in conventional baseball — which is also why balks exist only at those levels.', 'published'),
  ('ll-003', 'll', 'Leaving early', 'majors', 'Majors game. After a wild play ends, the catcher is still retrieving his mask near the backstop when R2 suddenly trots toward third. The pitcher has the ball near the mound but is not on the pitcher’s plate.', '["R2 must return — the play was over","Legal — runners are free to advance until the pitcher is set to deliver and the catcher is ready","Dead ball — runners may never advance between pitches","R2 is out for leaving early"]'::jsonb, 1, 'The leaving-early restriction only bites once the pitcher begins delivery with the catcher ready to receive. Before the pitcher and catcher are in position, the ball is live and runners advance at their own risk.', 'published'),
  ('ll-004', 'll', 'Leaving early', 'majors', 'Majors game. The batter-runner rounds first hard on a clean single and hesitates fifteen feet toward second. The pitcher gets the ball back and quickly steps onto the pitcher’s plate, claiming the runner must now return.', '["Correct — engaging the plate freezes all runners","The runner may still advance or return — a pitcher cannot trap a legitimately off-base runner by stepping on the plate","The runner is out if he does not return immediately","No pitch is declared"]'::jsonb, 1, 'A runner who is legitimately off his base (here, on his own hit) is not stopped by the pitcher stepping onto the plate. The pitcher must actually make a play; stepping on the rubber is not a magic freeze.', 'published'),
  ('ll-005', 'll', 'Leaving early', 'majors', 'Majors game. The umpires notice that on every pitch, all runners break the instant the pitcher’s arm starts forward, and the third-base coach can be heard telling them to go on first movement.', '["Nothing can be done beyond returning the runners","The manager may be warned and then ejected for deliberately instructing players to violate the rule","Each runner is automatically out after the second violation","The game is forfeited"]'::jsonb, 1, 'When leaving early is judged to be deliberate team instruction rather than a kid’s mistake, the remedy escalates to the bench: the manager can be warned or ejected for intentionally violating the rule.', 'published'),
  ('ll-006', 'll', 'Leaving early', 'majors', 'Majors game. The pitcher toes the plate ready to go. The catcher is in position facing him, mask on, but standing upright rather than crouched. The pitcher begins his delivery.', '["No pitch — the catcher must be in a squat","Legal — a catcher is “ready” with mask on and facing the pitcher; no squat is required","Quick pitch — ball on the batter","Time out is automatic until the catcher crouches"]'::jsonb, 1, '“Ready to receive” means mask on and facing the pitcher — nothing more. Runners are free to advance until both pitcher and catcher meet those elements, but once they do, the delivery may begin.', 'published'),
  ('ll-007', 'll', 'Leaving early', 'intermediate', 'Senior League game, R2. On the pitcher’s first movement to the plate, R2 takes off and steals third without a throw.', '["R2 is returned to second — he left before the ball reached the batter","Clean steal — the play stands","No pitch — runners may not steal on the first movement","R2 is out"]'::jsonb, 1, 'In Junior and Senior (and Intermediate) baseball, runners may leave with the pitch like in any conventional game. Sending the runner back is a Majors-and-below remedy only.', 'published'),
  ('ll-008', 'll', 'Baserunning & sliding', 'majors', 'Majors game. R2 tries to score on a single and dives headfirst across home plate just under the tag.', '["Safe — great slide","Out — a runner who slides headfirst while advancing is out in Majors and below","Safe, but the team is warned","The run counts only if the tag was late"]'::jsonb, 1, 'In the Little League divisions and below, sliding headfirst while advancing is an automatic out — even if the runner beats the tag. It is a safety rule, not a judgment call.', 'published'),
  ('ll-009', 'll', 'Baserunning & sliding', 'majors', 'Majors game. On a pickoff throw to first, R1 dives back headfirst and gets his hand on the bag before the tag.', '["Out — headfirst slides are illegal in Majors","Safe — the headfirst restriction only applies while advancing, not returning","Out, and the manager is warned","Safe only if the throw pulled the fielder off the bag"]'::jsonb, 1, 'The headfirst-slide rule applies to runners advancing to a base. Diving back to a base already reached is legal at every level.', 'published'),
  ('ll-010', 'll', 'Baserunning & sliding', 'majors', 'Majors game. The catcher, ball in hand, stands on the plate waiting. R3 comes home standing up at full speed and crashes into him without any attempt to slide or veer off.', '["Safe if he touched the plate first","Out — a runner must attempt to slide or avoid a fielder who has the ball and is waiting to tag","Obstruction on the catcher for blocking the plate","Both players are ejected automatically"]'::jsonb, 1, 'Little League has no “must slide” rule, but when the fielder has the ball and is waiting, the runner must make some attempt to slide or get around. Barreling straight in is an out, and flagrant contact can add an ejection.', 'published'),
  ('ll-011', 'll', 'Baserunning & sliding', 'majors', 'Majors game. Caught in no-man’s-land, R1 sprints in a wide arc through the outfield grass to get around the second baseman, who is chasing him with the ball. No batted ball is nearby.', '["Legal — a runner can run anywhere","Out if he runs more than three feet from his basepath to avoid the tag","Out only if he is touched","The basepath is always a straight line between the bases"]'::jsonb, 1, 'A runner’s basepath is set at the moment of the tag attempt: a straight line from the runner to the base. Deviating more than three feet from it to avoid a tag is an out. There is no violation until the defence actually attempts a tag.', 'published'),
  ('ll-012', 'll', 'Baserunning & sliding', 'majors', 'Majors game. Ball four. The batter-runner jogs to first, rounds it a step past the bag out of habit, and is immediately tagged by the alert first baseman before returning.', '["Out — the overrun protection does not apply on a walk","Safe — a batter-runner may overrun first on a walk and return immediately without liability","Out unless he turned toward foul territory","Dead ball — he must stay on the bag on a walk"]'::jsonb, 1, 'The overrun protection at first base applies even when the batter was awarded first on a walk, so long as he returns immediately. Turning left or right does not matter unless he actually attempts to advance.', 'published'),
  ('ll-013', 'll', 'Baserunning & sliding', 'majors', 'Majors game. R1 slides hard into second on a steal, beats the tag — and his slide knocks the entire bag loose from its anchor, leaving him lying beside the dislodged base.', '["Out when tagged while not touching the base","Safe — once he reached the base safely, no play can be made on him at the dislodged bag","He must chase the bag and hold on to it","Dead ball — he is awarded third for the faulty equipment"]'::jsonb, 1, 'When a runner’s impact dislodges the base after he has reached it safely, he cannot be played on at that base. He is not expected to follow the bag around or hover over its original spot.', 'published'),
  ('ll-014', 'll', 'Baserunning & sliding', 'majors', 'Majors game, R1 and R3, one out. R1 is tagged on a close play at second, believes he is out even though the umpire signalled safe, and jogs off across the infield toward his dugout. He is well onto the foul territory grass when the defence notices.', '["He can return to second any time before being tagged","He is out for abandoning the bases, and the ball stays live for R3","Dead ball — he returns to second with a warning","He is out, and the ball is dead immediately"]'::jsonb, 1, 'A runner who clearly gives up and heads for the dugout is out for abandonment once he has progressed well off the baseline. The ball remains live, so other runners may still advance at their own risk.', 'published'),
  ('ll-015', 'll', 'Baserunning & sliding', 'majors', 'Majors game. R1 is struck by the shortstop’s wild throw while running the bases; later in the same game, R2 collides with the third baseman who is bent over fielding a slow roller.', '["Both are automatic outs","Neither can ever be penalized","The thrown ball is nothing (runner has right of way); the batted-ball contact risks interference (fielder has right of way)","Both are obstruction on the fielders"]'::jsonb, 2, 'Right of way flips with the type of ball: on a thrown ball the runner has it, so being hit or bumped is ordinarily nothing; on a batted ball the fielder fielding it has it, so the runner who hinders him commits interference.', 'published'),
  ('ll-016', 'll', 'Appeals', 'intermediate', 'Junior League game. The defence believes R2 missed third scoring on a double. The pitcher steps off and fires the appeal throw — over the third baseman’s head and into the dugout.', '["Runners advance on the overthrow, and the defence may re-appeal once the ball is live","Runners advance on the overthrow, and the defence has lost the right to make any appeal","The appeal simply fails; runners hold","Dead ball — do-over"]'::jsonb, 1, 'An errant act during an appeal that kills the ball — like a throw out of play — counts as an attempted play and wipes out the right to any further appeal. Award the bases and move on.', 'published'),
  ('ll-017', 'll', 'Appeals', 'intermediate', 'Senior League game. Wanting to appeal a missed base, the pitcher stands on the pitcher’s plate with the ball, then backs off it with his free foot first before throwing to second.', '["Legal — how he steps off is irrelevant","Improper — disengaging for an appeal must be with the pivot foot first","Legal only if the umpire first calls time","An appeal may never start from the pitcher’s plate"]'::jsonb, 1, 'An appeal may be made directly from the pitcher’s plate, but a pitcher who chooses to disengage must step off with the pivot foot first. (Stepping back incorrectly with runners on risks a balk at levels that have them.)', 'published'),
  ('ll-018', 'll', 'Appeals', 'majors', 'Majors game. Before appealing a missed second base, the shortstop fakes a throw to third to freeze R3, never releasing the ball, then the defence completes the appeal at second.', '["The appeal is lost — the fake was a play","The appeal stands — a feint without releasing the ball is not a play or attempted play","Both the fake and the appeal are illegal","R3 is awarded home for the deke"]'::jsonb, 1, 'In baseball, only a genuine effort with a released throw (or an actual tag attempt) counts as a play. A feint costs the defence nothing, so the appeal right survives.', 'published'),
  ('ll-019', 'll', 'Appeals', 'majors', 'Majors game, R2. Deep fly caught in centre. R2, standing a stride behind second base, times the catch and takes off for third from that rolling start without ever re-touching the bag. The defence throws to second and the fielder stands on the base with the ball.', '["Safe — he was close enough to the bag","Out — a runner may not take a flying start; touching the base with the ball is an unmistakable appeal, no words needed","The defence must verbally announce the appeal first","R2 just returns to second"]'::jsonb, 1, 'Tagging up means re-establishing contact with the base after the catch. A flying start from behind the bag fails that, and the fielder holding the ball on the base while the runner is off is itself an unmistakable appeal.', 'published'),
  ('ll-020', 'll', 'Appeals', 'intermediate', 'Intermediate game. The batter-runner beats the play at first but his foot misses the bag entirely as he crosses it. A second later the first baseman, holding the ball, is still standing on the base.', '["Automatic out — he never touched first","He is considered to have touched the base once he passed it; only a proper, unmistakable appeal can retire him","He must go back and touch before the fielder does anything","Dead ball — umpire sorts it out"]'::jsonb, 1, 'A runner who passes a base is treated as having acquired it until the defence appeals. The play at first after the miss is an appeal play, not a force play — the defence must make the claim unmistakably.', 'published'),
  ('ll-021', 'll', 'Appeals', 'majors', 'Majors game, two out. R2 and R3 both race home on a hit; R3 misses the plate and R2, right behind him, touches it. R3 starts back toward the plate as the catcher takes the throw. The defence appeals R3’s miss.', '["R3 may still scramble back and touch the plate","R3 is out — once the following runner touched the plate, R3 can no longer return; as the third out, neither run scores","Only R3’s run is removed; R2’s counts","Both runs count — the plate was touched by someone"]'::jsonb, 1, 'A runner may not return to touch a missed plate after a following runner has legally touched it. The appeal out is the third out made on a runner who failed to reach home, so no run on the play scores.', 'published'),
  ('ll-022', 'll', 'Appeals', 'intermediate', 'Junior League game. R1 rounds second on a fly ball he thought would drop, and on his way back to first to tag up he cuts across the infield, missing second. The ball is dropped after all, so he re-touches first and runs again, this time stepping on second on his way to third.', '["Out on appeal — he missed second on the way back","The later touch of second while advancing corrects the earlier miss — no appeal will succeed","He must touch second twice to correct the miss","Dead ball — return him to first"]'::jsonb, 1, '“Last time by” is what counts: a runner’s most recent pass of a base is the one that must be legal. Touching second on the final advance supersedes the miss on the way back.', 'published'),
  ('ll-023', 'll', 'Appeals', 'majors', 'Majors game. The third out of the inning is recorded, and the defence then realizes R3 left third before a caught fly on that same play and scored. All the infielders are still in fair territory. The manager wants the run cancelled.', '["Too late — the inning is over","The pitcher takes the plate, the umpire calls “Play,” and the defence may execute the appeal for an advantageous fourth out","Appeals are impossible once a third out exists","The umpire cancels the run without any appeal needed"]'::jsonb, 1, 'Appeal rights survive the third out until the defence leaves fair territory. With everyone gone but the pitcher needed, the ball is made live from the pitcher’s plate and the appeal proceeds; a fourth out against a scoring runner cancels the run.', 'published'),
  ('ll-024', 'll', 'Mandatory play & re-entry', 'majors', 'Majors regular-season game, traditional batting order. A substitute enters at second base, plays three defensive outs, sits for an inning, then plays three more outs.', '["He has met mandatory play — six outs total","He has not — a substitute’s six defensive outs must be consecutive","Substitutes have no mandatory play requirement","He met it as long as he also batted"]'::jsonb, 1, 'Under the traditional batting order, a substitute must get six consecutive defensive outs before being removed. Starters are different: their six outs need not be consecutive because they carry re-entry rights.', 'published'),
  ('ll-025', 'll', 'Mandatory play & re-entry', 'majors', 'Majors game, traditional order. A starter is pulled in the third inning for a substitute. In the fifth, the manager wants the starter back in the game.', '["Never — removed players are done for the game","Allowed once the substitute has met mandatory play, and only in the starter’s original batting spot","Allowed anywhere in the order","Allowed only if the substitute is injured"]'::jsonb, 1, 'Starters have re-entry rights in Little League — a sharp difference from OBR — but the substitute must first satisfy mandatory play, and the starter must return to his own spot in the order. Violating either is protestable.', 'published'),
  ('ll-026', 'll', 'Mandatory play & re-entry', 'majors', 'Majors game, traditional order. A substitute is ejected for throwing his bat before reaching his six defensive outs. The manager sends the starter he replaced back onto the field.', '["Fine — the ejection frees the spot","Not allowed — if the substitute fails to meet mandatory play through injury or ejection, the starter may NOT re-enter","Allowed with the umpire-in-chief’s permission","The team plays a man short"]'::jsonb, 1, 'Re-entry hangs on the substitute completing mandatory play. When ejection or injury prevents that, the starter’s re-entry right dies with it — another player must fill the spot.', 'published'),
  ('ll-027', 'll', 'Mandatory play & re-entry', 'majors', 'Majors game using the continuous batting order. The coach freely rotates all twelve players through defensive positions inning by inning, with no player getting six consecutive outs.', '["Violation — six consecutive outs are always required","Legal — with a continuous order there is free defensive substitution, but every player must still total six defensive outs","Legal, and there is no defensive requirement at all","Only starters must reach six outs"]'::jsonb, 1, 'The continuous batting order brings free substitution, so nobody needs consecutive outs — but the six-defensive-out total still applies to every player. Everyone bats in the continuous order, which covers the offensive part.', 'published'),
  ('ll-028', 'll', 'Mandatory play & re-entry', 'majors', 'Majors game, continuous batting order, two out. The catcher of record is on second base. The coach sends in another player from the bench to run for him so he can put his gear on.', '["Illegal — courtesy runners do not exist in Little League","Legal — a courtesy runner is allowed for the pitcher or catcher of record with two outs","Legal for anyone at any time with a continuous order","Legal only in the last inning"]'::jsonb, 1, 'With two outs, the pitcher or catcher of record may be replaced on base by a courtesy runner. It keeps the game moving and is specifically contemplated by the mandatory-play interpretations.', 'published'),
  ('ll-029', 'll', 'Mandatory play & re-entry', 'majors', 'Majors game, traditional order. In the fourth inning a starter re-enters — but into a different spot in the batting order. The opposing manager notices right away, before the next pitch.', '["Nothing can be done during the game","It is a protestable violation that must be corrected before the next pitch or play","The re-entering player is ejected","The game is immediately forfeited"]'::jsonb, 1, 'A starter re-entering into the wrong batting spot is an improper substitution — a protestable rule violation to be resolved before the next pitch or play. Caught later, it goes to the local Board of Directors instead.', 'published'),
  ('ll-030', 'll', 'Pitching & balks', 'majors', 'Majors game, R1 and R2. The pitcher rushes his delivery before the batter’s hands and eyes are up.', '["Balk — runners advance one base","Ball on the batter — Majors has no balks, and a quick pitch there is always ruled a ball","Strike if the pitch is in the zone","Warning only"]'::jsonb, 1, 'There are no balks in Majors and below. A quick pitch — delivered before the batter is reasonably set — is penalized as a ball to the batter at that level, runners on or not.', 'published'),
  ('ll-031', 'll', 'Pitching & balks', 'intermediate', 'Junior League game, R1. The pitcher quick-pitches before the batter is reasonably set in the box.', '["Ball on the batter, runners hold","Balk — with runners on base in Intermediate and above, a quick pitch is a balk","No penalty — the batter must be ready","The pitch counts as delivered"]'::jsonb, 1, 'At Intermediate (50/70), Junior, and Senior, the quick pitch is treated like conventional baseball: a balk with runners on, a ball with the bases empty. In Majors it would only ever be a ball.', 'published'),
  ('ll-032', 'll', 'Pitching & balks', 'intermediate', 'Senior League game, R1 and R3. From the rubber, the pitcher steps toward third and fakes a throw — disengaging as he does — then steps toward first and throws over, nearly picking R1 off.', '["Balk — the fake-to-third, throw-to-first move is illegal","Legal in Little League — a feint to an occupied third with a proper step is allowed, and the disengaged pitcher may then throw to first","Balk — a pitcher may only feint to second","Legal only if he threw to third first"]'::jsonb, 1, 'Little League still permits feinting to second or third (occupied, with a step) — the famous third-to-first move remains legal here, unlike modern professional rules, provided the feint takes the pitcher off the plate before the throw to first.', 'published'),
  ('ll-033', 'll', 'Pitching & balks', 'intermediate', 'Intermediate game, R1. In the set position, the pitcher’s free foot swings back past the back edge of the pitcher’s plate — and he then throws to first for a pickoff.', '["Legal — the foot position is meaningless","Balk — once the free foot passes the back edge, he must pitch, except to throw to second on a pickoff of an advancing runner","Legal because the runner was stealing","Illegal pitch — ball on the batter"]'::jsonb, 1, 'Once any part of the free foot passes the back edge of the pitcher’s plate, the pitcher is committed to delivering — the lone exception is a throw to second on a legitimate pickoff. Coming back to first from there is a balk.', 'published'),
  ('ll-034', 'll', 'Pitching & balks', 'intermediate', 'Junior League game, R2. While engaged and taking the sign, the pitcher fumbles the ball; it drops and dribbles four feet, staying inside the foul lines.', '["No penalty — pick it up and resume","Balk — a dropped ball while engaged that stays inside the foul lines is an illegal pitch, a balk with a runner on","Ball on the batter in every case","Dead ball, do-over"]'::jsonb, 1, 'A ball dropped while engaged is an illegal pitch if it stays inside the foul lines — a balk with runners on at levels that have balks. If it crosses a foul line, it is instead a ball to the batter and stays live.', 'published'),
  ('ll-035', 'll', 'Pitching & balks', 'majors', 'Majors game, bases empty. The pitcher wanders two steps off the mound with the ball, then fires a surprise pitch to the catcher without touching the pitcher’s plate.', '["Legal — no runners were on","Ball on the batter — pitching while not in contact with the pitcher’s plate is one of the two illegal pitches penalized even with the bases empty","Strike if in the zone","No pitch, warning only"]'::jsonb, 1, 'Two illegal pitches are penalized even with nobody on: the quick pitch and a pitch thrown while not in contact with the pitcher’s plate. Both are ruled a ball to the batter, at all levels.', 'published'),
  ('ll-036', 'll', 'Pitching & balks', 'majors', 'Majors game, R1. The pitcher steps off the pitcher’s plate but keeps both hands together on the ball, then immediately steps back on and starts his motion.', '["Legal — he disengaged properly","Improper — after disengaging he must separate his hands and drop them to his sides before re-engaging","Automatic balk in all divisions","Legal as long as the runner was on the base"]'::jsonb, 1, 'Disengaging does not require separating the hands immediately, but before stepping back onto the plate the hands must come apart and drop to the sides. That protects runners and batters from a de facto quick pitch.', 'published'),
  ('ll-037', 'll', 'Pitching & balks', 'majors', 'Majors game. The coach visits the mound to settle his pitcher in the third inning, then comes out to talk to the same pitcher again later in the same inning.', '["Fine — visits are unlimited in Majors","The pitcher must be removed from the mound on the second visit in the same inning","The coach is ejected","The second visit costs a ball to the batter"]'::jsonb, 1, 'In Majors, a coach gets one free visit to a pitcher per inning and two per game; the next visit at either threshold forces the pitcher’s removal from the mound. (Minor League allows one extra at each level.)', 'published'),
  ('ll-038', 'll', 'Pitching & balks', 'intermediate', 'Intermediate game, R1. The pitcher sets up in a stance that blends windup and set features — pivot foot on the plate, free foot slightly ahead, hands together in front. The offensive coach demands a balk for an “illegal hybrid stance.”', '["Balk — a pitcher must clearly declare windup or set","No violation — nothing in the pitching rules prohibits a hybrid stance, provided all the usual delivery rules are followed","Illegal pitch — ball on the batter","Time — the umpire must make him restart in a legal stance"]'::jsonb, 1, 'The interpretations are explicit: no rule prevents a hybrid pitching stance. The pitcher must still obey every normal delivery requirement, but the stance itself is not a balk.', 'published'),
  ('ll-039', 'll', 'Catch & carry', 'majors', 'Majors game, R1 and R2, one out. The first baseman makes a fine running catch on a foul pop and his momentum carries him down the dugout steps, ball held high.', '["Catch stands, play on — hustle play","No catch — foul ball","Catch stands, but the ball is dead and both runners advance one base from the time of pitch","Catch stands and runners are frozen"]'::jsonb, 2, 'A fielder who legally catches a fly ball and then steps or falls into dead-ball territory records the out, but the ball is dead and every runner is awarded one base from the time of the pitch.', 'published'),
  ('ll-040', 'll', 'Catch & carry', 'majors', 'Majors game. Chasing a pop-up toward his own dugout, the catcher gloves the ball with one foot on the dugout lip and the other foot planted on the top step inside.', '["Legal catch — one foot was on the lip","No catch — a foot on the ground inside the dugout at the moment of the catch makes him “inside,” and no valid catch can be made there","Legal catch, ball dead, runners advance","Foul ball only if it would have landed in the dugout"]'::jsonb, 1, 'The lip counts as playing surface, but a foot on a step or the floor inside the dugout does not. With a foot down inside, the fielder is “inside the dugout” and cannot legally catch the ball.', 'published'),
  ('ll-041', 'll', 'Catch & carry', 'majors', 'Same chase, different footwork: the catcher gloves the pop-up with one foot on the dugout lip and the other foot in the air above the steps.', '["No catch — part of him was over the dugout","Legal catch — a foot on or over the playing surface with neither foot down in dead-ball territory is valid","Legal only if he does not fall in afterward","Umpire’s discretion"]'::jsonb, 1, 'A catch is valid when the fielder has a foot on or over the playing surface (the lip included) and no foot on the ground in the dead-ball area. If he then falls into the dugout, the catch stands and the catch-and-carry award applies.', 'published'),
  ('ll-042', 'll', 'Catch & carry', 'majors', 'Majors game, R2. The third baseman fields a ground ball and his errant throw to first sails into the stands.', '["Catch-and-carry: one base from time of pitch","This is not catch-and-carry at all — it is an overthrow, awarded under the thrown-ball rules (two bases)","The runner returns to second","Dead ball, no awards"]'::jsonb, 1, 'Catch-and-carry covers only batted fly balls carried into dead-ball territory after a catch. A wild throw out of play is a different animal with its own award — two bases for a throw by an infielder on the first play.', 'published'),
  ('ll-043', 'll', 'Catch & carry', 'majors', 'Majors game. An outfielder sprints toward the open bullpen gate, launches himself, and gloves the fly ball in mid-air before landing entirely inside the bullpen (a dead-ball area by ground rules), never having touched live-ball ground during the catch.', '["No catch — a fielder who dives into dead-ball territory with neither foot on or over the playing surface cannot make a valid catch","Catch, ball dead, one-base award","Catch, play on","Home run"]'::jsonb, 0, 'The catch must begin from the playing surface: one or both feet on or over live-ball ground. Diving fully into a dead-ball area with neither foot on or above the playing surface makes a valid catch impossible.', 'published'),
  ('ll-044', 'll', 'Interference', 'majors', 'Majors game. A bunt dies right in front of the plate. The catcher springs out to field it and tangles legs with the batter-runner leaving the box; both stumble. The umpire judges nobody meant anything by it.', '["Interference — the batter must yield","Obstruction — the catcher must yield","Nothing — incidental tangle/untangle contact between catcher and batter-runner is part of the play","Dead ball, replay the pitch"]'::jsonb, 2, 'The classic tangle/untangle: incidental contact between the catcher fielding the ball and the batter-runner starting to first is nothing. Signal safe — “that’s nothing” — and let the play continue.', 'published'),
  ('ll-045', 'll', 'Interference', 'majors', 'Same bunt, but this time the catcher, ball still on the ground, deliberately shoves the batter-runner off his line to first with both hands.', '["Still nothing — contact at the plate is always incidental","Interference on the batter-runner","Obstruction on the catcher — flagrant contact that impedes the batter-runner is penalized","Ejection but no base award"]'::jsonb, 2, 'The tangle/untangle exemption ends where flagrant or deliberate contact begins. A catcher who intentionally impedes the batter-runner commits obstruction; a batter-runner who flagrantly impedes the catcher commits interference.', 'published'),
  ('ll-046', 'll', 'Interference', 'intermediate', 'Senior League game, strike three in the dirt, batter-runner takes off. Because the ball squirted toward the first-base dugout, the catcher’s throw comes from foul ground — and the batter-runner, running in fair territory outside the running lane, is hit in the shoulder by it.', '["Interference — he was outside the lane, automatic out","Not interference — with the throw coming from the foul side, running in fair territory is legal on an uncaught third strike, unless he interfered intentionally","Dead ball, batter out, runners return","The throw hitting him makes him out regardless of position"]'::jsonb, 1, 'The running-lane rule still exists on an uncaught third strike, but when the throw originates from foul ground, the fair side is the legal place to be — being struck there is not interference absent intent.', 'published'),
  ('ll-047', 'll', 'Interference', 'majors', 'Majors game. While their teammate bats, the next batter stands outside the dugout swinging a bat to stay loose.', '["Fine — that is what the on-deck circle is for","Not allowed — there is no on-deck position in Majors and below, and the next batter may not pick up a bat until it is their turn","Allowed with a helmet on","Allowed only if the field has no fence"]'::jsonb, 1, 'The on-deck circle exists only in Intermediate, Junior, and Senior divisions. In Majors and below, the next batter gets a helmet on and waits — no bat in hand until their turn at bat.', 'published'),
  ('ll-048', 'll', 'Interference', 'intermediate', 'Junior League game. A batting weight is left lying in the on-deck circle. A foul pop drifts that way and the catcher, tracking the ball, trips over it and the ball drops.', '["Tough luck — play on","Unnecessary equipment on the field can draw an interference call against the team at fault — here the offence, so the batter can be ruled out","Automatic dead ball, no penalty","The catcher is charged with an error"]'::jsonb, 1, 'Equipment not in use must be cleared from the on-deck circle and the field. When it affects a play, the umpire may rule interference against the offending team — costing an out or bases depending on who was hurt by it.', 'published'),
  ('ll-049', 'll', 'Interference', 'majors', 'Majors game, R1. A ground ball rolls toward the second baseman, and R1, running from first, is bumped as the fielder charges the ball; the fielder bobbles it and everyone is safe. The umpire judges the contact hindered the fielder.', '["Obstruction — award R1 second","Interference — the fielder fielding a batted ball has the right of way; R1 is out and the ball is dead","Nothing — the contact was accidental","Both players penalized"]'::jsonb, 1, 'On a batted ball the fielder attempting to field it has the right of way. A runner who hinders him — intent or not — commits interference: the runner is out, the ball is dead, and other runners return.', 'published'),
  ('ll-050', 'll', 'Interference', 'majors', 'Majors game, R3, one out. The batter squares to bunt, fouls it straight down, and the ball spins into fair territory where R3, sprinting home on the squeeze, is struck by it in fair ground before it passes any fielder.', '["Run scores if he beats the ball home","R3 is out, the ball is dead, and the batter is awarded first base","Foul ball — replay","R3 returns to third, no out"]'::jsonb, 1, 'A runner struck in fair territory by a fair batted ball before it passes an infielder is out and the ball is dead — same fundamentals as any level of baseball. The batter gets first on the play.', 'published'),
  ('ll-051', 'll', 'Double first base', 'majors', 'Majors game on a field with a double first base. A chopper down the line lands squarely on the orange half of the bag without touching the white.', '["Fair — it hit the base","Foul — a ball touching only the orange portion is foul","Umpire’s judgment on the bounce","Dead ball"]'::jsonb, 1, 'Only the white half of a double first base is fair territory. A batted ball striking just the orange half — without first touching or bounding over the white — is a foul ball.', 'published'),
  ('ll-052', 'll', 'Double first base', 'majors', 'Majors game, double first base, bang-bang play on a ground ball. Which halves of the base are the fielder and the batter-runner each supposed to use?', '["Either player may use either half","Fielder on the orange, runner on the white","Fielder on the white, batter-runner on the orange for his first attempt at the bag","Both must touch both halves"]'::jsonb, 2, 'When a play is being made on the batter-runner, the defence takes the white half and the batter-runner’s first touch must be the orange half — that separation is the entire point of the safety base.', 'published'),
  ('ll-053', 'll', 'Double first base', 'majors', 'Majors game, close play at the double first base. The batter-runner beats the throw but steps only on the white half. Before he returns to the bag, the defence clearly appeals that he used the wrong half.', '["Safe — he touched some part of the base","It is treated like a missed base — the umpire rules on the appeal and the batter-runner is out","He just gets sent back to touch the orange half","The defence must tag him physically to win the appeal"]'::jsonb, 1, 'On a play at first, touching only the white half is treated the same as missing the base. If the defence makes an unmistakable appeal before he returns to the bag, he is out; if they let him return, the miss is cured.', 'published'),
  ('ll-054', 'll', 'Double first base', 'majors', 'Majors game, double first base. The batter-runner laces a double-turned-single into the gap — no play anywhere near first — and touches the orange half rounding the bag before retreating to stand on it.', '["Out on appeal — with no play, he must use the white half","Legal — with no chance of a play at first, either half may be touched","He must re-touch the white half to be safe","Interference"]'::jsonb, 1, 'The white/orange split only governs plays at the bag. On balls to the outfield with no chance of a play at first, the batter-runner may touch either portion.', 'published'),
  ('ll-055', 'll', 'Double first base', 'majors', 'Majors game, double first base, R1 standing on the bag. On a pickoff throw, R1 dives back and grabs the orange half as the tag comes down on him.', '["Safe — any part of the double base counts","Out — for pickoffs, tag-ups, and leaving the base, the runner may only use the white half","Safe if the first baseman was on the white half","No play allowed at a double base"]'::jsonb, 1, 'Once the batter-runner has become a runner occupying first, the orange half stops being his: for tagging up, taking a position, and pickoff plays, only the white half is the base.', 'published'),
  ('ll-056', 'll', 'Double first base', 'intermediate', 'Senior League game, double first base, uncaught third strike. The batter-runner sprints as the catcher retrieves the ball and fires to first, where the first baseman stretches with a foot on the orange half a beat before the runner hits the white half.', '["Runner safe — the fielder must use the white half","Runner out — on an uncaught third strike, both the defence and the batter-runner may use either half of the base","No play — batters cannot run on strike three","Runner safe — he touched the correct half"]'::jsonb, 1, 'The uncaught third strike is the exception at the double base: throws often come from foul ground, so both the fielder and the batter-runner may legally use either the orange or the white half.', 'published'),
  ('ll-057', 'll', 'Batting & the box', 'majors', 'Majors game, nobody on, two strikes. The batter swings through strike three and the ball skips off the dirt past the catcher to the backstop. The batter takes off for first.', '["He can take first if he beats the throw","He is out — in Majors and below the batter is out on strike three whether or not the catcher holds it","He is safe automatically because the ball got away","The pitch is replayed"]'::jsonb, 1, 'Running on an uncaught third strike exists only in Intermediate (50/70), Junior, and Senior baseball. In Majors and below, strike three retires the batter no matter where the ball ends up.', 'published'),
  ('ll-058', 'll', 'Batting & the box', 'intermediate', 'Intermediate (50/70) game, R1 on first, one out. Strike three bounces off the catcher’s glove and rolls away. The batter sprints for first.', '["He may run — the ball was not caught","He is out — with first base occupied and fewer than two outs, the batter may not advance on an uncaught third strike","He is out only if the catcher tags him","R1 must advance for the batter to run"]'::jsonb, 1, 'Even at levels where the uncaught third strike is live, the batter cannot run when first base is occupied with fewer than two outs — the rule that prevents cheap force double plays. With two outs he could run.', 'published'),
  ('ll-059', 'll', 'Batting & the box', 'majors', 'Majors game. Annoyed by a called strike, the batter steps out of the box without asking for time just as the pitcher delivers the next pitch, which crosses the plate.', '["No pitch — the box was empty","The pitch counts, and the benefit of the doubt on ball or strike goes to the pitcher","Automatic strike regardless of location","The batter is out"]'::jsonb, 1, 'A batter who leaves the box without time being granted is at his own risk: the pitch counts, and the umpire gives the pitcher the benefit of the doubt. Batters cannot step in and out at will.', 'published'),
  ('ll-060', 'll', 'Batting & the box', 'intermediate', 'Junior League game, R1. The pitcher has begun his motion when the batter abruptly steps out of the box, and the startled pitcher interrupts his delivery.', '["Balk — he stopped his motion with a runner on","No balk — the batter induced the stop; the umpire calls time and both players restart","Strike on the batter as a penalty","The batter is ejected"]'::jsonb, 1, 'When the batter causes the interruption by stepping out mid-delivery, no balk or illegal pitch is charged. The umpire calls time, everyone resets, and the sequence starts over cleanly.', 'published'),
  ('mech-001', 'mech60', 'Rotations', 'sixty', '60-ft diamond, nobody on base. The batter lifts a deep fly into the left-center gap and U2 goes out for the catch/no-catch. Which rotation is the crew now in?', '["Full rotation — everyone moves clockwise","Fill rotation — U3 alone fills the vacancy","U2 Fill — U2 covers first and second","No rotation — everyone stays home"]'::jsonb, 0, 'With no runners in scoring position (nobody on, or R1 only), U2 or U3 going out triggers the Full rotation: PU rotates up to third, U3 slides over to second, and U1 takes the batter-runner at first before releasing home.', 'published'),
  ('mech-002', 'mech60', 'Rotations', 'sixty', '60-ft diamond, Full rotation in progress after U2 went out on a fly ball with nobody on. The batter-runner is being waved around second toward third. Who has the play at third base?', '["U3, sprinting back from second","The plate umpire, in foul territory at Po3","U1, cutting across the infield","Nobody — the crew concedes the call to the closest umpire"]'::jsonb, 1, 'In the Full rotation the plate umpire moves up the line to cover third, staying in foul territory all the way to Po3, and must arrive 60 feet ahead of the runner to be set for a tag play.', 'published'),
  ('mech-003', 'mech60', 'Rotations', 'sixty', '60-ft diamond, nobody on. U3 goes out on a fly ball down the left-field line. In the Full rotation that follows, what is U1’s assignment?', '["Stay anchored at first for the whole play","Rotate immediately to third base","Observe the batter-runner’s touch of first, then release to cover home at PoP","Go out to back up U3 on the catch"]'::jsonb, 2, 'U1 watches the batter-runner touch first, then releases to home plate, mirroring the lead runner so as to arrive at PoP 60 feet ahead of the runner. The umpire covering second picks up the batter-runner back into first once U1 releases.', 'published'),
  ('mech-004', 'mech60', 'Rotations', 'sixty', '60-ft diamond, nobody on, U3 out on a fly ball. The batter-runner rounds first and dives back in on the throw behind him. U1 has already released toward home. Whose call is it at first?', '["U1 must run back — first base is always his","U2, who covered second in the rotation, picks up the batter-runner back into first","The plate umpire from the plate area","U3, coming back in from the outfield"]'::jsonb, 1, 'Once U1 releases to home in the Full rotation, the umpire who rotated to second (here U2) is responsible for plays back into first. U1 never returns once he has released.', 'published'),
  ('mech-005', 'mech60', 'Rotations', 'sixty', '60-ft diamond, runner on first only. A fly ball drives F8 toward the right-center gap and U2 goes out. Which rotation applies?', '["Fill rotation, because a runner is on base","Full rotation — R1 only is still “no runners in scoring position”","U2 Fill","Reverse rotation"]'::jsonb, 1, 'The trigger for the Full rotation is no runners in scoring position, which covers both bases empty and a runner on first only. The Fill rotation is reserved for runners in scoring position.', 'published'),
  ('mech-006', 'mech60', 'Rotations', 'sixty', '60-ft diamond, runner on second only. U3 goes out on a drive toward the left-field line. What does U2 do?', '["Stay planted at his starting position","Rotate to third while PU takes second","Move into the Restricted Area and cover both second and third","Follow U3 out as backup on the catch"]'::jsonb, 2, 'With a runner in scoring position, U2 or U3 leaving triggers the Fill rotation: the remaining middle umpire fills the vacancy from the Restricted Area and owns both second and third, slipping to the outside once his responsibilities become singular.', 'published'),
  ('mech-007', 'mech60', 'Rotations', 'sixty', '60-ft diamond, bases loaded. U2 goes out on a fly ball to center. Where does the plate umpire go?', '["Up to third, as in the Full rotation","Nowhere — PU stays home at PoP for the entire play","Halfway up the third-base line to float between third and home","To the mound to direct traffic"]'::jsonb, 1, 'With runners in scoring position the crew uses the Fill rotation, and the plate umpire never leaves home: runs are the priority. With R3, PU lines up the tag-up at the dirt circle and then gets back to PoP aggressively.', 'published'),
  ('mech-008', 'mech60', 'Rotations', 'sixty', '60-ft diamond, runners on second and third. U1 goes out on a fly ball that pushes F9 toward the right-field line. Which rotation does the crew use?', '["Fill rotation, because runners are in scoring position","Full rotation","U2 Fill — it is always the answer when U1 leaves, regardless of the runners","No rotation is needed when U1 goes out"]'::jsonb, 2, 'Anytime U1 leaves to cover catch/no-catch, the crew is in the U2 Fill — the position of the runners never changes that. U2 fills the Restricted Area and takes first and second, and U3 moves to Po3.', 'published'),
  ('mech-009', 'mech60', 'Rotations', 'sixty', '60-ft diamond, U2 Fill rotation: U1 went out on a fly ball. U2 is working from the Restricted Area covering first and second. The play ends with only one runner still moving, heading back into first. What should U2 do?', '["Stay deep in the Restricted Area no matter what","Slip to the outside now that the responsibility is singular","Hand first base off to the plate umpire","Sprint to the outfield-side of second base"]'::jsonb, 1, 'The Restricted Area is only for multiple responsibilities. Once an umpire’s coverage narrows to a single base, he slips to the outside and works the play from there, chest to ball.', 'published'),
  ('mech-010', 'mech60', 'Rotations', 'sixty', '60-ft diamond, runners on first and third. U3 goes out on a deep fly to left. In the Fill rotation, what is U1’s role?', '["Rotate to home to free up PU","Move to Po1 and act as the “crew saver,” using proper use of eyes on everything he can","Cover second and third from the Restricted Area","Trail the batter-runner to second"]'::jsonb, 1, 'In the Fill rotation U1 moves to Po1, holds first, and is the crew saver — eyes disciplined and on the whole play so he can bail the crew out on anything unexpected. U2 fills for second and third, and PU stays home.', 'published'),
  ('mech-011', 'mech60', 'Rotations', 'sixty', '60-ft diamond, runner on third, one out. U2 goes out on a medium fly ball to center and R3 tags. How does the plate umpire handle the tag-up?', '["Runs up the line to third to watch the retouch from close range","Lines up R3’s retouch at the dirt circle, then returns aggressively to PoP for the play at the plate","Delegates the retouch to U1 across the diamond","Watches from the slot without moving"]'::jsonb, 1, 'In the Fill rotation the plate umpire keeps the retouch at third when R3’s umpire situation demands it: he lines up the tag-up at the dirt circle, then hustles back to PoP because the play at the plate is his and runs are the priority.', 'published'),
  ('mech-012', 'mech60', 'Rotations', 'sixty', '60-ft diamond crew in the pre-game conference. A new umpire asks: “When exactly do we run the Full rotation?” What is the correct answer?', '["Any fly ball to the outfield, no matter who goes out","Only with the bases completely empty","When U2 or U3 goes out with no runners in scoring position — bases empty or R1 only","Whenever the plate umpire feels like rotating"]'::jsonb, 2, 'Full rotation = NRiSP (nobody on or R1 only) and the umpire leaving is U2 or U3. If U1 is the one who leaves, it is always the U2 Fill instead, and with runners in scoring position it becomes the Fill rotation.', 'published'),
  ('mech-013', 'mech60', 'Rotations', 'sixty', '60-ft diamond, runner on second. U3 goes out on a fly ball. A teammate expects the plate umpire to rotate up to third the way he does with nobody on. Does he?', '["Yes — PU always covers third when U3 leaves","No — with a runner in scoring position PU stays at the plate and U2 fills for both second and third","Yes, but only if the ball is caught","No — U1 covers third instead"]'::jsonb, 1, 'The Full rotation (PU up to third) is only used with no runners in scoring position. With R2, the crew is in the Fill rotation: PU never abandons the plate because the runner can score, and U2 owns second and third from the Restricted Area.', 'published'),
  ('mech-014', 'mech60', 'Rotations', 'sixty', '60-ft diamond, nobody on, ball in the right-center gap with U2 out. U1 releases to home. The batter-runner takes a wide turn at first — who is watching him now, and from where?', '["U3, covering second in the rotation, picks up the batter-runner back into first","U1, walking backward toward home","PU from Po3","U2 from the outfield grass"]'::jsonb, 0, 'In the Full rotation with U2 out, U3 moves to Po2 opposite the throw for plays at second and also inherits plays back into first once U1 releases to the plate.', 'published'),
  ('mech-015', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond. A slicing fly ball forces F9 to sprint toward the right-field foul line. Whose catch/no-catch is it?', '["U1 — F9 moving toward the line is his area","U2 — he owns all three outfielders","PU, since the ball threatens fair/foul","U3, rotating behind the play"]'::jsonb, 0, 'On the 60-ft diamond U1’s area of responsibility is F9 moving toward the right-field line. U2 has F7 and F9 moving in, back, or toward center, plus everything F8 does; U3 mirrors U1 on the left-field line.', 'published'),
  ('mech-016', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond. F8 turns and races straight back toward the center-field fence on a deep drive. Which umpire goes out?', '["U1","U3","U2 — anything F8 does belongs to him","Nobody — a ball to the fence is obvious"]'::jsonb, 2, 'F8 belongs to U2 in every direction. A ball threatening the fence is one of the “3 Fs” (fair/foul, fence, fielders converging) where an umpire absolutely must be out for catch/no-catch and boundary calls.', 'published'),
  ('mech-017', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond. A fly ball pushes F7 drifting toward center field, away from the foul line. Whose ball is it?', '["U3 — F7 is always his","U2 — F7 moving toward center belongs to U2, not U3","PU, because no line is threatened","U1, crossing behind second"]'::jsonb, 1, 'U3 only owns F7 moving toward the left-field line. When F7 moves in, back, or toward center, that fly ball is U2’s. Reading the fielder’s direction — not the ball — is what defines the area of responsibility.', 'published'),
  ('mech-018', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond. On a drive into the left-center gap, both U2 and U3 break toward the outfield at the same time. How is the conflict resolved?', '["Whoever called it first keeps it","The crew defers to U2 — he is the quarterback — and U3 recovers into the rotation, unless the ball is on the line","The crew defers to U3 as the senior base umpire","Both stay out and split the call"]'::jsonb, 1, 'If two umpires take the same fly ball, the crew defers to U2, the quarterback on all fly balls to the outfield. The other umpire recovers and rotates. The exception is a ball on the foul line, which stays with the line umpire.', 'published'),
  ('mech-019', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond. U3 went out on a fly ball that dropped. The play turns into a rundown between third and home. May U3 come back in to help?', '["No — once out, an umpire never re-enters under any circumstance","Yes — assisting on a rundown is the one exception to “go out and stay out,” waiting for the play to come toward him before calling himself in","Yes, and he should immediately take over the lead call","Only if the plate umpire physically waves him in"]'::jsonb, 1, 'The rule is go out and stay out — except that an umpire may return to assist in a rundown, waiting for the play to move away from his partner before calling himself into it.', 'published'),
  ('mech-020', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond. U1 goes out on a fly ball down the right-field line. As the fielder tracks it, how should U1 physically work the play?', '["Run directly at the fielder to get as close as possible","Run parallel to the fielder, as far as the play allows, and get stopped and set before the attempted catch","Backpedal along the foul line watching the ball","Stand still at his starting spot and take the long look"]'::jsonb, 1, 'Going out means running parallel to the fielder to avoid being straight-lined, getting as far out as the play allows, and being stopped and set before the catch attempt — then using timing and proper use of eyes before signaling.', 'published'),
  ('mech-021', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond. A high pop-up comes down on the infield grass behind the mound, with F4 and F6 converging and gloving it chest-high. Who has catch/no-catch?', '["U2, closest to the play","The plate umpire — all catch/no-catch on the infield grass is his","Whichever base umpire the glove opens toward","U1, because the ball is right-side"]'::jsonb, 1, 'The plate umpire owns all catch/no-catch on the infield grass, and any infield ball gloved above the fielder’s waist. The open glove theory only takes over on balls played below the waist off the grass.', 'published'),
  ('mech-022', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond. A sinking line drive forces F6 to lunge low, glove opening toward the third-base side. The catch is at his shoe tops. Who rules catch or trap?', '["PU — every infield ball is his","U3 — the open glove theory sends the call to the umpire the glove opens toward","U2 — F6 always belongs to U2","U1 — the throw is going his way"]'::jsonb, 1, 'On balls fielded below the waist, the open glove theory applies: the umpire toward whom the fielder’s glove opens has catch/no-catch. That is exactly why base umpires must be able to see the shoe tops of the fielder in front of them.', 'published'),
  ('mech-023', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond, crack of the bat on a ball to the outfield. What is the “read step” every umpire is instructed to take?', '["A step toward home plate to hear the crew chief","Opening with the ball, chest to ball, body sideways parallel to the foul line, to read fly ball vs. base hit, the fielders, and the partners","Two hard steps toward the outfield on every batted ball","A step backward to widen the view"]'::jsonb, 1, 'The read step opens the umpire with the ball — chest to ball, posture parallel to the line — to sort out three things: is it a fly ball or a base hit, where are the fielders moving (which defines AOR), and what are the partners doing.', 'published'),
  ('mech-024', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond, nobody on. A fly ball hangs in U2’s area and U2 is reading whether to go out. Meanwhile U3 takes a couple of quiet early steps toward second base. What is U3 doing?', '["Abandoning his post — a mechanics error","Taking a cheat step toward his rotation assignment so he arrives on time if U2 goes; if U2 stays, he simply returns to his base","Trying to draw a throw from the outfielder","Covering for the plate umpire"]'::jsonb, 1, 'The cheat step is an early, small move toward the base the umpire will cover if the rotation happens. It buys a head start while the partner reads the fly ball, and costs nothing — if the partner stays, the umpire just steps back to his base.', 'published'),
  ('mech-025', 'mech60', 'Fly Ball Coverage', 'sixty', '60-ft diamond. A lazy single drops cleanly in front of F8, who fields it on one hop. U2 sprints into the outfield anyway. Why is this wrong?', '["It is not wrong — always go out on any ball to the outfield","Base hits are not fly balls: going out on a clean hit abandons second base and strands the crew, which is exactly what the read step is meant to prevent","U2 may never leave the infield under any circumstance","Only U1 and U3 are allowed to go out"]'::jsonb, 1, 'Umpires go out on fly balls in their area, not on clean base hits. On a clean hit U2 moves to Po2 opposite the throw for the runner sliding in. Umpires leaving on base hits was the specific problem the read-step emphasis was created to fix.', 'published'),
  ('mech-026', 'mech60', 'Fair / Foul', 'sixty', '60-ft diamond. A chopper down the first-base line is fielded by F3 well in front of the bag, right on the chalk. Whose fair/foul call is it?', '["U1 — he is standing right there","The plate umpire — he has both lines up to but not including the front edge of the base","U2, from the middle","Joint call between PU and U1"]'::jsonb, 1, 'The plate umpire owns fair/foul on both lines up to but not including the front edge of first and third — including any ball fielded in front of the bag or that stops short of it. U1 takes over from the front edge and beyond.', 'published'),
  ('mech-027', 'mech60', 'Fair / Foul', 'sixty', '60-ft diamond. A hard ground ball bounds over the third-base bag itself and kicks into the outfield. Who makes the fair/foul call?', '["PU — all fair/foul belongs to the plate","U3 — he has everything from the front edge of the base and beyond, including balls bounding over the bag","U2, with the best cross angle","No call is needed on a bounding ball"]'::jsonb, 1, 'From the front edge of the base and beyond — bounding in the air, on the ground, or fielded even with or past the bag — the line belongs to U3 (or U1 on the other side). Short of the front edge it is the plate umpire’s call.', 'published'),
  ('mech-028', 'mech60', 'Fair / Foul', 'sixty', '60-ft diamond. Earlier in the play U1 abandoned the right-field line to take a play, and now a looping ball lands near that line beyond first base. Who has fair/foul?', '["U1 hustles back to the line to make the call","The plate umpire — once U1 abandons the line, PU assumes the entire line and U1 never comes back for fair/foul","U2 splits the difference","The call defaults to fair"]'::jsonb, 1, 'An umpire who abandons his line never comes back to make a fair/foul decision. The plate umpire assumes the entire foul line the moment U1 or U3 leaves it — one of the reasons PU “holds the line” at PoP when not rotating.', 'published'),
  ('mech-029', 'mech60', 'Fair / Foul', 'sixty', '60-ft diamond, runner on third. A swinging bunt dribbles up the third-base line and R3 breaks home, crossing directly between the plate umpire and the rolling ball. What is the crew’s built-in answer to this?', '["PU calls it anyway on his best guess","This is the “pinch”: with R3 blocking PU’s look between home and third, fair/foul passes to U3","The ball is automatically foul once a runner screens the umpire","U1 takes the call from across the diamond"]'::jsonb, 1, 'With R3, the runner can block the plate umpire’s sight line on a ball between home and third. That is the pinch situation, and the fair/foul decision passes to U3 — something the crew pre-signals so nobody is surprised.', 'published'),
  ('mech-030', 'mech60', 'Fair / Foul', 'sixty', '60-ft diamond. A ground ball is rolling up the first-base line, untouched, still short of the bag and wobbling between fair and foul territory. When should an umpire declare it?', '["Immediately, so everyone can stop running","Not until the ball is touched or settles — never before it reaches first or third on its own","Once it crosses the halfway point of the baseline","Only after the offensive coach asks"]'::jsonb, 1, 'A rolling ball short of the base is declared only when it is touched or settles. Calling it early is a classic error: the ball can still spin fair or kick foul, and a premature “foul” kills a live play that might have stayed fair.', 'published'),
  ('mech-031', 'mech60', 'Fair / Foul', 'sixty', '60-ft diamond. A fly ball drifts down the line into the left-field corner, about 10 feet off the chalk, with F7 giving chase. The umpire on the call knows it will land near the line. When does he name it fair or foul?', '["While it is still in the air, to help the runners","Only after the ball is touched by the fielder or touches the ground","Never — outfield balls are not named","As soon as the fielder waves his arms"]'::jsonb, 1, 'A fly ball to the outfield is never named fair or foul until it is touched or lands. Once it does, a ball that becomes fair or foul within 20 feet of the line gets a verbal and visual call; obvious fouls far off the line do not.', 'published'),
  ('mech-032', 'mech60', 'Fair / Foul', 'sixty', '60-ft diamond. From his angle, U3 is 100% certain a bounced ball nicked the batter in the box, but the plate umpire says nothing and the defense is playing on. What should U3 do?', '["Nothing — it is exclusively the plate umpire’s call","Yell “Foul ball!” instantly","Give PU a beat to make the call first; if he does not, stop everything by aggressively calling “Time!”, then sort out batter-in-the-box (foul) vs. out of the box (out)","Wait until the end of the play and mention it quietly"]'::jsonb, 2, 'A base umpire who is completely certain the batted ball touched the batter gives the plate umpire first crack, then kills the play with an aggressive “Time!” Afterward the crew decides: touched in the box is foul; touched outside the box over fair territory makes the batter-runner out.', 'published'),
  ('mech-033', 'mech60', 'Fair / Foul', 'sixty', '60-ft diamond. A towering pop-up drifts into foul ground halfway between home and first, with F3 camping under it. How do PU and U1 divide the play?', '["They bracket the fielder: PU holds the line for fair/foul while U1 shades toward the fence, with catch/no-catch decided by the infield principles","Both converge on the fielder from the same side","U1 takes everything; PU watches the batter","PU takes everything; U1 protects first base"]'::jsonb, 0, 'Pop-ups between home and first (or third) are bracketed: the plate umpire stays on the line for the fair/foul element and U1/U3 shades to the fence side. Who signals catch/no-catch follows the infield rules — PU above the waist or on the grass, open glove below.', 'published'),
  ('mech-034', 'mech60', 'Positioning', 'sixty', '60-ft diamond. A new U1 sets up about six feet behind the first-base bag, directly in line with F3. What is wrong with this pre-pitch position?', '["Nothing — closer is always better","He must be at least 10–12 feet from the base, never parallel with or in front of the fielder, and outside the fielder’s 2–3 step “halo”","He should be in fair territory instead","He should stand on the foul line itself"]'::jsonb, 1, 'The starting position rules: never closer than 10–12 feet to the base in front of you, never parallel with or ahead of the fielder, slightly outside the fielder’s halo, and always able to see the fielder’s shoe tops for a sinking line drive.', 'published'),
  ('mech-035', 'mech60', 'Positioning', 'sixty', '60-ft diamond, runner on first only. Where does U2 set up?', '["B position","C position — on the 60-ft diamond, R1 (and R1+R3) puts U2 in C","Inside the diamond behind the mound","Shallow center field"]'::jsonb, 1, 'On the 60-ft diamond U2 works outside the diamond and picks his spot by the runners: C with R1 or R1+R3, B anytime a runner is on second, and preference with R3 only or nobody on.', 'published'),
  ('mech-036', 'mech60', 'Positioning', 'sixty', '60-ft diamond, runner on second. U2 wants to stay in the C position because he likes the view. What does the manual say?', '["Position is always umpire preference","Anytime there is a runner on second, U2 uses the B position","U2 must move inside the diamond with R2","U2 should stand directly behind second base"]'::jsonb, 1, 'With any runner on second base, U2 is in B on the 60-ft diamond. C is for R1 or R1+R3; only with R3 alone or bases empty does personal preference decide.', 'published'),
  ('mech-037', 'mech60', 'Positioning', 'sixty', '60-ft diamond, runner on first. The base umpires want to use the relaxed standing “wide receiver” set they used all last inning with the bases empty. Is that allowed?', '["Yes — stance is always a comfort choice","No — anytime a runner is on any base, every umpire uses the hands-on-knees set; wide receiver is only an option with nobody on, and only if the whole crew agreed pre-game","Yes, but only for U2","No — hands-on-knees is required at all times"]'::jsonb, 1, 'With runners on, hands-on-knees is mandatory for every umpire. The walk-the-line wide receiver set is a bases-empty option that the whole crew must adopt together, decided in the pre-game conference.', 'published'),
  ('mech-038', 'mech60', 'Positioning', 'sixty', '60-ft diamond. When is an umpire supposed to work from the Restricted Area rather than from the point of a base?', '["Whenever he wants a better view of the outfield","When his responsibilities are multiple — covering more than one base; once they become singular he uses the point of the base","Only on plays at the plate","Never — the Restricted Area is for the 2-umpire system only"]'::jsonb, 1, 'The Restricted Area (between the mound and the second-base cutout) is used only when covering multiple bases, staying chest to ball with depth to keep angles open. With a single responsibility, the umpire works from the point of the base instead.', 'published'),
  ('mech-039', 'mech60', 'Positioning', 'sixty', '60-ft diamond. Where exactly is “Po3,” the spot U3 owns on plays at third?', '["On the infield-side corner of the bag in fair territory","The topside (outfield) corner of third base, in foul territory between the foul line and the coach’s box","Ten feet up the left-field line toward home","Directly behind the third-base coach"]'::jsonb, 1, 'Point of third is the topside outfield corner of the bag, in foul ground between the line and the coach’s box — close enough to own the “real estate,” out of everyone’s way, chest to ball, and positioned for tag plays.', 'published'),
  ('mech-040', 'mech60', 'Positioning', 'sixty', '60-ft diamond, between innings. Where does each member of the 4-umpire crew stand while the defense warms up?', '["All four gather behind the mound","PU on the defensive side in foul territory near the line; U1, U2, U3 in shallow right, center, and left field respectively, moving in when the ball goes down to second","Each umpire stands on his base","PU at the backstop, base umpires along the first-base fence"]'::jsonb, 1, 'Neutral positions: the plate umpire works the defensive-side foul territory (watching the on-deck batter, counting warm-up pitches, alerting at two remaining, one-minute limit), while U1/U2/U3 stand in shallow right/center/left and return to their starting spots when the ball is thrown down.', 'published'),
  ('mech-041', 'mech60', 'Positioning', 'sixty', '60-ft diamond, nobody on. A routine ground ball goes to F6, throw over to first. What is the plate umpire doing during this play?', '["Standing still behind the plate","Trailing the batter-runner toward first — watching for a runner’s lane violation, an overthrow going out of play, and helping U1 with a pulled foot or swipe tag if asked","Rotating to third in case of an error","Following the throw to the shortstop"]'::jsonb, 1, 'With nobody on, PU trails the batter-runner up the line. He owns any tag attempt on the BR before the runner’s lane, watches the lane violation and out-of-play overthrows, and offers pulled-foot/swipe-tag help to U1 on request — then returns to PoP.', 'published'),
  ('mech-042', 'mech60', 'Tag-Ups & Touches', 'sixty', '60-ft diamond, runners on second and third, one out. U2 goes out on a deep fly to center and both runners tag. Who is watching R2’s retouch at second?', '["U2, glancing back over his shoulder","U3 — the retouch advances to the umpire at the base ahead of the runner","U1 from across the diamond","PU handles both retouches at once"]'::jsonb, 1, 'When an umpire leaves, retouch responsibility advances to the umpire positioned ahead of the runner: with U2 out, U1 has first, U3 has second, and PU has third. Trying to watch a tag-up behind you while covering a base ahead is how calls get missed.', 'published'),
  ('mech-043', 'mech60', 'Tag-Ups & Touches', 'sixty', '60-ft diamond, runner on second and third. U1 goes out on a fly ball down the right-field line. Who has the retouches at first and second?', '["PU has both","U2 has both retouches at first and second","U3 takes first, PU takes second","Nobody — retouches are waived when U1 leaves"]'::jsonb, 1, 'When U1 goes out, U2 picks up the retouches at both first and second — consistent with the U2 Fill, where U2 owns everything on that side of the infield. U3 keeps third (or PU keeps it in situations where U3 has second and third).', 'published'),
  ('mech-044', 'mech60', 'Tag-Ups & Touches', 'sixty', '60-ft diamond, runner on first only. U2 goes out on a deep drive and R1 holds to tag. The crew is in a Full rotation. Who watches R1’s retouch at first?', '["U3, covering second","PU on his way to third","U1 — the one exception: in the Full rotation with R1 only, U1 takes R1’s retouch before releasing","U2 from the outfield"]'::jsonb, 2, 'Normally retouches advance to the umpire ahead of the runner, but the manual carves out one exception: with R1 only in the Full rotation, U1 keeps R1’s retouch at first — he is right there before his release home.', 'published'),
  ('mech-045', 'mech60', 'Tag-Ups & Touches', 'sixty', '60-ft diamond, Full rotation running with nobody on (U3 out on the catch attempt). The batter-runner is circling the bases on a ball in the gap. Match the touches: who has first, second, third, and home?', '["U1 has first and home, U2 has second, PU has third","PU has first, U1 has second, U2 has third and home","U1 has everything until relieved","U2 has first and second, PU has home, U1 has third"]'::jsonb, 0, 'Full rotation touch map: U1 takes the batter-runner’s touch of first and then home after releasing; the middle umpire who stayed (U2 here) has second; the plate umpire has third.', 'published'),
  ('mech-046', 'mech60', 'Tag-Ups & Touches', 'sixty', '60-ft diamond, runner on first, ground ball to F6 — a tailor-made double play. As the feed comes to second, what is the 2026 point-of-emphasis footwork for U2?', '["Charge the bag to get on top of the pivot","One step in the direction of the throw for an angle, stopped and locked with eyes to the base — then drift with eyes down on the runner and fielder for any late infractions","Back away toward the outfield for the wide view","Straddle second base before the throw arrives"]'::jsonb, 1, 'Double-play footwork: take one step toward the throw to create an angle, be stopped and locked at the moment of the force with eyes on the base, and afterward drift with eyes down on the runner and pivot fielder to catch slide or contact infractions.', 'published'),
  ('mech-047', 'mech60', 'Crew Signals & POEs', 'sixty', 'Any diamond, 4-umpire crew. The count runs to 3-2 on the batter. What is the whole crew expected to do before the next pitch?', '["Nothing — counts are the plate umpire’s business","Every umpire signals the 3-2 count, flagging the coming “action pitch” for the whole crew","Only PU and U1 exchange a nod","The crew resets to bases-empty positions"]'::jsonb, 1, 'On any count reaching 3-2, all four umpires signal it. The next pitch can produce a checked swing ask, a strikeout-throw-out double play, or ball four with runners moving — the crew signal keeps everyone alert to all of it.', 'published'),
  ('mech-049', 'mech60', 'Crew Signals & POEs', 'sixty', 'Any diamond. The batter tries to hold up on an inside pitch and the ball grazes his hands mid-half-swing. Why must the plate umpire check the swing immediately here?', '["To decide whether to eject the pitcher","Because the ruling hinges on it: if he swung it is a dead-ball strike, if he held up it is a hit-by-pitch — and that must be settled now, not retroactively","Because the ball is live either way and runners are advancing","It is only checked if the offense complains"]'::jsonb, 1, 'A half-swing plus hit-by-pitch is an automatic, immediate check: swing means dead-ball strike, no swing means the batter is awarded first. Handling it on the spot avoids the mess of unwinding the play after the fact.', 'published'),
  ('mech-051', 'mech60', 'Crew Signals & POEs', 'sixty', 'Any diamond, pre-pitch. What does the crew’s “DOO” mnemonic tell each umpire to think through before every pitch?', '["Distance, Obstruction, Overthrow","Whether his job on a ball in play is to move Down to the point of his base, Out for catch/no-catch in his area, or Over to another base in rotation","Defense, Offense, Outs","Drive, Observe, Officiate"]'::jsonb, 1, 'Every pitch, every umpire already knows what he will “DOO” on a ball in play: Down to the point of his base, Out for a fly ball in his area, or Over to a base he covers in rotation — signaled pre-pitch by pointing, initiated by PU but done by all.', 'published'),
  ('mech-054', 'mech60', 'Tag Plays & the Wedge', 'sixty', 'Any diamond, tag play developing at a base. Where does the umpire start when finding the wedge?', '["Straddling the base","5–7 feet directly behind the fielder receiving the throw, without impeding the fielder’s lateral movement","15–18 feet away at a fixed 90-degree angle","On the runner’s track into the base"]'::jsonb, 1, 'Current instruction: start 5–7 feet behind the fielder receiving the throw. That puts the umpire on a parallel track with the fielder, allows quick relative adjustments, and takes fewer steps to hold the wedge — while staying off the fielder’s lateral track and the runner’s path.', 'published'),
  ('mech-056', 'mech60', 'Tag Plays & the Wedge', 'sixty', 'Any diamond, throw arriving on a tag play. The umpire is behind the fielder, and the runner starts his slide. Whom does the umpire adjust with as the tag is applied — the fielder or the runner?', '["The fielder, all the way through the play","The runner: follow the fielder to the play, but adjust with the runner as the tag is applied, getting the runner sliding toward you","Neither — lock in and never move","The base coach’s signals"]'::jsonb, 1, 'Follow the fielder, adjust with the runner. The fielder takes you to the developing play, but the fielder must bring the tag to the runner — so at the moment of truth you adjust with the runner, keeping him sliding toward you to avoid being blocked out.', 'published'),
  ('mech-048', 'mechBig', 'Crew Signals & POEs', 'big', 'Any diamond. Two strikes on the batter. He offers at a low pitch and the ball skips past the catcher. Nobody on the defense asks for help on the swing. What does the plate umpire do?', '["Wait — check the swing only if the defense appeals","Check the swing with the base umpire immediately, without being asked: two-strike half-swings are an automatic check","Call the batter out on his own read","Declare no pitch and reset"]'::jsonb, 1, 'With two strikes, umpires check the swing immediately without waiting for an appeal — especially on a third strike not caught, where whether the batter struck out determines whether he can run. Waiting invites chaos and gives one side an advantage.', 'published'),
  ('mech-050', 'mechBig', 'Crew Signals & POEs', 'big', 'Any diamond, 2026 season. When the plate umpire himself checks a swing, what new mechanic may he use so the crew cannot mistake it for anything else?', '["Pointing at the batter with his indicator","Both hands out with open palms — an unmistakable two-handed checking signal","Removing his mask and holding it overhead","A closed fist pumped twice"]'::jsonb, 1, 'New for 2026: the plate umpire may check a swing using two hands with open palms, a movement distinct enough that it cannot be confused with any other plate mechanic.', 'published'),
  ('mech-052', 'mechBig', 'Crew Signals & POEs', 'big', 'Any diamond. Who initiates the pre-pitch responsibility signals in the 4-umpire system, and who is required to give them?', '["U2 initiates as the quarterback; only middle infield umpires signal","The plate umpire initiates, but every umpire on the crew must signal","The crew chief initiates; signals are optional","Signals are only used with runners in scoring position"]'::jsonb, 1, 'Pre-pitch communication is initiated by the plate umpire but must be done by all four: each umpire points to his responsibility for the situation. Early, continuous, audible and visual communication is the backbone of the system.', 'published'),
  ('mech-053', 'mechBig', 'Tag Plays & the Wedge', 'big', 'Any diamond. In wedge theory, what exactly is “the wedge” the umpire is trying to put his eyes into?', '["The triangle between the base, the mound, and the umpire","The area between the fielder’s base-side hip and the incoming runner’s base-side hip, where the tag attempt happens","The cutout of dirt around the base","The gap between the umpire and the nearest coach"]'::jsonb, 1, 'The wedge is the space between the fielder’s base-side hip and the runner’s base-side hip — getting your eyes in there as the two come together is what lets you actually see the tag instead of guessing at it.', 'published'),
  ('mech-055', 'mechBig', 'Tag Plays & the Wedge', 'big', 'Any diamond. The saying in wedge theory is that “the base will not take us to the play.” What actually takes the umpire to the play?', '["The runner’s path alone","The three variables of a play — ball, fielder, and runner — moving together; the base is only a reference point","The throw’s trajectory","A pre-determined spot chosen before the pitch"]'::jsonb, 1, 'A play is ball, fielder, and runner coming together — the definition never mentions the base. Running to a pre-set spot invites being straight-lined; moving with those three variables keeps the angle alive as the play changes direction.', 'published'),
  ('mech-057', 'mechBig', 'Tag Plays & the Wedge', 'big', 'Any diamond, wedge theory. What is “the window,” and how does the umpire get into it?', '["The gap between the bases, reached at full sprint","The space between the runner and the fielder at the point of the tag attempt, reached with final controlled “quiet steps” — staying patient and never defaulting to one side too soon","The umpire’s field of vision when standing still","The opening in the fence used for photographers"]'::jsonb, 1, 'The window is the space between runner and fielder at the moment of the tag. Quiet steps — small, controlled final movements — put your eyes there. Committing early to one side is how umpires get straight-lined out of the call.', 'published'),
  ('mech-058', 'mechBig', 'Rotations', 'big', 'Big diamond (50/70 or 90-ft), nobody on base. U1 goes out on a fly ball toward the right-field line. Which rotation covers the vacancy at first?', '["U2 Drift — U2 covers first and second","PU Trail: the plate umpire trails the batter-runner and owns his touch and any play at first, releasing home as the BR touches second","Full rotation with U3 covering first","No coverage is needed at first with nobody on"]'::jsonb, 1, 'On the big diamond with nobody on and U1 out, the crew uses PU Trail: the plate umpire trails the batter-runner to first, takes all plays on him there, and hustles back to PoP once the BR reaches second. U2 goes to Po2 and U3 to Po3.', 'published'),
  ('mech-059', 'mechBig', 'Rotations', 'big', 'Big diamond, runner on first only. U1 goes out on a fly ball. Does the plate umpire trail the batter-runner like he would with nobody on?', '["Yes — PU Trail applies anytime U1 leaves","No — with any runner on base it becomes the U2 Drift: PU stays at PoP, and U2 drifts to the right side to take everything at first and second","No — U3 sprints across to cover first","Yes, but only until the ball lands"]'::jsonb, 1, 'PU Trail is a bases-empty rotation. With runners on, a run can score, so PU stays home and U2 drifts into the working area on the right side of the infield, responsible for all plays at first and second. U3 holds third at Po3.', 'published'),
  ('mech-060', 'mechBig', 'Rotations', 'big', 'Big diamond, nobody on. U2 goes out from his outside position on a gap fly ball. Which rotation follows?', '["Reverse rotation","Full rotation: PU moves toward third, U3 covers second, and U1 stays at Po1 until the batter-runner reaches second, then releases to the plate","U2 Drift","No rotation — U2 has no coverage to replace"]'::jsonb, 1, 'With no runners in scoring position and U2 (or U3) going out, the big diamond uses the Full rotation, just like the small field: PU drifts up toward third, the remaining middle umpire takes second, and U1 releases home once the lead runner reaches second.', 'published'),
  ('mech-061', 'mechBig', 'Rotations', 'big', 'Big diamond, runner on first, U3 goes out on a fly ball down the left-field line. In the Full rotation, when exactly does U1 leave first base for the plate, and what does he say?', '["Immediately at the crack of the bat, silently","When the lead runner reaches second base, releasing in foul territory to PoP while telling U2, “I’m going home”","Only when the plate umpire waves him in","He never releases with a runner on first"]'::jsonb, 1, 'U1 holds Po1 (observing the touches) until the lead runner reaches second, then releases in foul territory to the plate, verbally handing off with “I’m going home” so U2 knows he now owns first as well as second.', 'published'),
  ('mech-062', 'mechBig', 'Rotations', 'big', 'Big diamond, runner on second only. U3 goes out on a drive to left-center. What is U1’s assignment in the Reverse rotation?', '["Hold Po1 and never move","Pivot into the infield between first and second, take the batter-runner’s touch of first, and slide with the BR — he owns the BR at both first and second","Rotate behind the plate umpire to third","Take the runner at third once R2 advances"]'::jsonb, 1, 'In the Reverse rotation U1 pivots inside between first and second, watching the batter-runner touch first, then slides with him toward second — all plays on the BR at first and second are U1’s. U2 slides with the lead runner toward third.', 'published'),
  ('mech-063', 'mechBig', 'Rotations', 'big', 'Big diamond, runner on second only, U3 out on the fly ball. R2 tags and takes off for third on the catch. Who has the play at third, and how did he get there?', '["PU, rotating up the line","U2 — he dropped toward the mound between second and third, took R2’s tag-up, slid with R2, and stays at third once R2 commits","U3, doubling back from the outfield","U1, cutting across the mound"]'::jsonb, 1, 'That is the heart of the Reverse rotation: U2 drops toward the mound on the second-to-third side, owns R2’s retouch and any play back into second, then slides with R2 to third and stays there for the duration once the runner commits.', 'published'),
  ('mech-064', 'mechBig', 'Rotations', 'big', 'Big diamond, runner on third only. U2 — positioned outside with R3 only — goes out on a fly ball. Who covers the batter-runner at first and second?', '["U1 pivots into the infield and takes the BR at both first and second","PU trails the batter-runner","U3 crosses the diamond to first","Nobody — the BR is on his own until third"]'::jsonb, 0, 'With R3 only and U2 out, U1 pivots into the working area between first and second to see the BR’s touch and owns him at first and second. PU stays home for R3, and U3 stays at Po3 — a Reverse-family rotation.', 'published'),
  ('mech-065', 'mechBig', 'Rotations', 'big', 'Big diamond, runner on third only, fewer than two outs. U3 goes out on a deep fly to left. R3 retreats to tag. Who lines up the tag-up at third, and who ends up covering third base itself?', '["PU lines up R3’s tag-up and then returns aggressively to PoP; U2 uses the working area to move toward third and covers R3 back into third and the BR at third","U1 takes both the tag-up and the base","PU stays at third for the whole play; nobody covers home","U2 lines up the tag-up from center field"]'::jsonb, 0, 'With U3 gone, PU clears the catcher to line up R3’s retouch, then sprints back to PoP for the play at the plate. U2 works toward third through the working area, taking R3 back into third or the BR arriving there. U1 pivots for the BR at first and second.', 'published'),
  ('mech-066', 'mechBig', 'Rotations', 'big', 'Big diamond, runners on first and second, one out. U3 goes out on a deep fly ball that is caught, and R2 tags. Which rotation does the crew use — and why is it special?', '["Reverse rotation, like every other RiSP situation","Full rotation: with fewer than two outs and the ball caught, PU reads R2 tagging and moves to third, letting U2 take R2’s tag-up and stay in the infield","U2 Drift","PU Trail"]'::jsonb, 1, 'R1+R2 with U3 out is the special case: if the ball is caught with fewer than two outs and R2 tags, the crew runs a Full rotation — PU takes third, U1 watches R1’s tag-up and then rotates home once R2 advances. With two outs or the ball not caught, it is the Reverse instead.', 'published'),
  ('mech-067', 'mechBig', 'Rotations', 'big', 'Big diamond, runners on first and second, two outs. U3 goes out on a fly ball that drops in the gap. Which rotation applies now?', '["Full rotation — R1+R2 is always Full when U3 leaves","Reverse rotation: with two outs (or the ball not caught) U1 pivots with the BR for first and second, and U2 slides with R1 toward third","U2 Drift","No rotation with two outs"]'::jsonb, 1, 'The Full-rotation exception for R1+R2 requires fewer than two outs and a caught ball (a tag-up situation). With two outs nobody tags — everyone runs — so the crew uses the standard Reverse: U1 pivots with the BR, U2 slides with R1 to third, PU stays home.', 'published'),
  ('mech-068', 'mechBig', 'Rotations', 'big', 'Big diamond, bases loaded. U1 goes out on a fly ball pushing F9 toward the line. Map the coverage behind him.', '["PU stays at PoP for the plate; U2 drifts into the infield between first and second for everything at those bases, including R1’s and R2’s retouches; U3 holds Po3 with R3’s retouch","PU trails the batter-runner; U3 covers home","U2 goes out with U1 to bracket the catch; U3 covers three bases","The crew collapses to a 2-umpire system"]'::jsonb, 0, 'U1 leaving with runners on is always the U2 Drift on the big diamond: U2 owns first and second (touches, plays, and the retouches by R1 and R2), U3 keeps third with R3’s retouch, and the plate umpire never leaves home.', 'published'),
  ('mech-069', 'mechBig', 'Rotations', 'big', 'Big diamond, bases loaded, one out. U3 goes out on a drive to the left-center gap. In the Reverse rotation, U2 “slides with R1.” What does U2’s full plate of responsibilities look like?', '["Just the force at second","R2’s retouch, R3 back into third, R2 back into second, R1 into second, and the plays at third on R2, R1, or the batter-runner as they arrive","Only plays at third base","The batter-runner at first and second"]'::jsonb, 1, 'U2 drops toward the mound on the second-to-third side and lets the ball take him to the play: he owns R2’s tag-up, runners back into second and third, lead runners into second, and — once the lead runner commits — the plays at third. U1 pivots for the BR at first and second.', 'published'),
  ('mech-070', 'mechBig', 'Rotations', 'big', 'Big diamond, runner on first. A fly ball hangs toward right-center. A newer umpire wonders why U2 never seems to go out for catch/no-catch in this situation. What is the reason?', '["U2 is lazy positioning himself","With R1 (and most runners-on situations) U2 is inside the diamond in the B position, so he has no outfield fly-ball responsibility at all — U1 and U3 split the outfield","U2 is saving energy for the rundowns","U2 must always stay within 10 feet of second base"]'::jsonb, 1, 'When U2 sets up inside the diamond (R1, R2, R1+R2, R1+R3, R2+R3, bases full), he is not responsible for any fly ball to the outfield. U1 covers F8 straight in/back all the way to the right-field line and U3 covers F8 toward the left-field line plus everything F7 does.', 'published'),
  ('mech-071', 'mechBig', 'Rotations', 'big', 'Big diamond, Reverse rotation (runner on second, U3 out). The batter-runner tries to stretch his hit and is thrown out sliding into second. Who made that call?', '["U2, from the third-base side","U1 — in the Reverse rotation he slides with the batter-runner and owns him at both first and second","PU, ranging up from home","U3, who returned from the outfield"]'::jsonb, 1, 'The Reverse rotation gives U1 the batter-runner start to finish on the right side: the touch at first, plays back into first, and the play on the BR at second. U2 is occupied sliding with the lead runner toward third.', 'published'),
  ('mech-072', 'mechBig', 'Rotations', 'big', 'Big diamond, runners on second and third. U3 goes out. R3 tags on the caught fly ball. Who is responsible for lining up R3’s retouch at third?', '["U2, sliding toward third","The plate umpire — he clears the catcher, lines up R3’s tag-up, then returns aggressively to PoP","U1 from the working area","Nobody — the retouch is U3’s even from the outfield"]'::jsonb, 1, 'In the Reverse rotation with R3, the plate umpire handles R3’s retouch — clear the catcher, line up the tag-up, then get back to PoP for the play on that same runner at the plate. U2 is busy with R2’s tag-up and the coverage toward third.', 'published'),
  ('mech-073', 'mechBig', 'Rotations', 'big', 'Big diamond crew comparing notes with a 60-ft crew. On the 60-ft diamond, U1 going out always produces the “U2 Fill.” What is the equivalent set of answers on the big diamond?', '["Identical — U2 Fill in all cases","Nobody covers for U1 on the big diamond","With nobody on it is PU Trail; with any runner on base it is the U2 Drift","U3 always crosses to cover first"]'::jsonb, 2, 'Big-diamond answer when U1 leaves: bases empty, the plate umpire trails the batter-runner (PU Trail); any runners on, U2 drifts to the right side for first and second (U2 Drift) while PU stays home.', 'published'),
  ('mech-074', 'mechBig', 'Fly Ball Coverage', 'big', 'Big diamond, nobody on. F8 sprints straight back on a deep drive to dead center. Whose catch/no-catch is it?', '["U1","U2 — with nobody on he is outside and owns F7 to F9, including fielders going straight in or straight back","U3","PU from behind the plate"]'::jsonb, 1, 'With nobody on (or R3 only), U2 works outside and his area runs from F7 to F9, including balls taking those fielders straight in or straight back. U1 and U3 take their outfielders moving toward the respective foul lines.', 'published'),
  ('mech-075', 'mechBig', 'Fly Ball Coverage', 'big', 'Big diamond, runner on first. The same deep drive sends F8 straight back toward the center-field fence. Whose ball is it now?', '["U2, same as with nobody on","U1 — with U2 inside, U1’s area expands to cover F8 straight in and back, all the way to the right-field line","PU sprints out for it","U3 automatically, since U2 is inside"]'::jsonb, 1, 'Once runners put U2 inside the diamond, the outfield is split two ways: U1 takes F8 straight in/straight back plus everything to the right-field line, and U3 takes F8 moving toward the third-base line plus all of F7. The runner situation changes the answer to the identical batted ball.', 'published'),
  ('mech-076', 'mechBig', 'Fly Ball Coverage', 'big', 'Big diamond, runners on first and second. A drive into the left-center gap takes F8 hard toward the left-field line, with F7 converging. Which umpire goes out?', '["U2 from inside the diamond","U3 — F8 moving toward the third-base line, or F7 moving in any direction, is his when U2 is inside","U1 — he owns all of F8","PU, since the fielders are converging"]'::jsonb, 1, 'With U2 inside, U3’s area is F7 in any direction plus F8 moving toward the left-field line. Converging fielders make it a must-cover ball (one of the 3 Fs). U1 only has F8 when the fielder goes straight in, straight back, or toward right.', 'published'),
  ('mech-077', 'mechBig', 'Fly Ball Coverage', 'big', 'Big diamond, runner on second. On a fly ball to right-center, both U1 and U3 break out at the same time. Who keeps it?', '["U3, because he started closer to the ball","U1 — with runners in scoring position the crew defers to U1 so the remaining umpires stay ahead of the runners; U3 recovers and rotates","U2 sorts it out from the infield","Whoever yells louder"]'::jsonb, 1, 'The deference rule flips with the runner situation: bases empty or R3 only, defer to U2; with R1 or runners in scoring position, defer to U1, because losing U3 (who recovers into the rotation) keeps the crew front-loaded ahead of the runners.', 'published'),
  ('mech-078', 'mechBig', 'Fly Ball Coverage', 'big', 'Big diamond, nobody on. U1 and U2 both take two hard steps toward a fly ball in right-center. Who backs off?', '["U2 backs off — U1 outranks him","U1 backs off — with nobody on, the crew defers to U2 and U1 recovers into the rotation","Both continue out together","PU picks one by pointing"]'::jsonb, 1, 'With nobody on or R3 only, U2 is the deference answer on shared fly balls, exactly like the 60-ft system. The reversal to U1 only happens when runners on base put U2 inside the diamond.', 'published'),
  ('mech-079', 'mechBig', 'Fly Ball Coverage', 'big', 'Big diamond, runner on third only. How is outfield fly-ball coverage divided among the base umpires?', '["Like all other runners-on situations: U1 and U3 split everything","Like nobody on: U2 is outside, so U1 has F9 to the line, U2 has F7 through F9 straight in/back, and U3 has F7 to the line","PU takes all fly balls with R3","Nobody goes out with a runner on third"]'::jsonb, 1, 'R3 only is the exception among runners-on situations: U2 still sets up outside the diamond, so the coverage (and the defer-to-U2 rule) works exactly as with the bases empty.', 'published'),
  ('mech-080', 'mechBig', 'Fly Ball Coverage', 'big', 'Big diamond. Which three kinds of fly balls are the “3 Fs” that an umpire absolutely must go out on when they are in his area?', '["Fastballs, fouls, and fences","Balls that threaten fair/foul, balls that threaten the fence or boundary, and balls with fielders converging","Fly balls, flares, and force plays","Any ball hit past the first fielder"]'::jsonb, 1, 'The 3 Fs: Fair/foul (a ball in flight threatening the line), Fence (possible home run or ground-rule double), and Fielders converging. Those are the plays where a close-up look is irreplaceable — plus any catch attempt below the waist by a charging fielder.', 'published'),
  ('mech-081', 'mechBig', 'Fly Ball Coverage', 'big', 'Big diamond, runners on first and third. A can-of-corn fly ball settles toward F9, who barely moves. Nobody goes out. Who has the catch/no-catch if something goes wrong?', '["U2 from the B position","The plate umpire — if no one goes out on a ball to the outfield, PU rules on catch/no-catch","U1 retroactively","The call is forfeited"]'::jsonb, 1, 'On routine balls where no umpire goes out, the plate umpire carries catch/no-catch from PoP. The crew’s goal is still to have the appropriate umpire out on every true fly ball in an area of responsibility.', 'published'),
  ('mech-082', 'mechBig', 'Fly Ball Coverage', 'big', 'Big diamond. An umpire commits and goes out on a fly ball near the fence. The ball drops, and chaos erupts on the bases behind him. What does he do?', '["Sprint back in to help with the bases","Stay out — he ruled on the catch and the boundary; his partners cover the bases, and he only re-enters to assist a rundown when the play allows","Follow the batter-runner around the bases","Take over the lead runner wherever he goes"]'::jsonb, 1, 'Go out and stay out. The rotation exists precisely so the remaining three umpires can absorb the base coverage. The lone exception is calling yourself into a rundown after waiting for the play to move away from the partner working it.', 'published'),
  ('mech-083', 'mechBig', 'Positioning', 'big', 'Big diamond, runner on first. Where does U2 set up before the pitch?', '["Outside the diamond behind second, like the 60-ft system","Inside the diamond in the “B only” position: heels or toes on the grass/dirt line between first and second, on the tangent line from the apex of home plate through the mound cutout, square to the third-base foul line","Directly behind the mound","In shallow center field"]'::jsonb, 1, 'With runners on (except R3 only), big-diamond U2 works inside in “B only” — on the first-to-second grass line along the tangent from the plate’s apex through the mound cutout, square to the third-base line. C, or moving outside, is used only when the infielders’ positioning warrants it.', 'published'),
  ('mech-084', 'mechBig', 'Positioning', 'big', 'Big diamond, nobody on. Where does U2 work, and what limits his spot?', '["Inside in the B position","Outside the diamond — no more than 1–2 steps into the outfield grass or heels on the infield arc, either side of second, never in the batter’s direct line of sight (no straight-away center), square to the plate","Anywhere in center field he likes","Standing on second base"]'::jsonb, 1, 'Bases empty (or R3 only), U2 is outside: within a step or two of the grass line behind second, on whichever side he prefers, no further toward first/third than the line from the plate through the mound cutout, out of the batter’s sight line, square to the plate, with halos around F4 and F6.', 'published'),
  ('mech-085', 'mechBig', 'Positioning', 'big', 'Big diamond, runner on third only. Inside or outside for U2?', '["Inside — any runner means inside","Outside, exactly as with nobody on: R3 only is the one runners-on situation where U2 stays outside","His choice with no constraints","Behind third base to help with R3"]'::jsonb, 1, 'R3 only keeps U2 outside the diamond. Every other runner configuration (R1, R2, and combinations) brings U2 inside to B — which is also what strips his outfield fly-ball coverage in those situations.', 'published'),
  ('mech-086', 'mechBig', 'Positioning', 'big', 'Big diamond. F3 is holding a runner on first and then, on the next batter, plays way back behind the bag. What must U1 do between those pitches?', '["Stay in the exact same spot for consistency","Move up or back with F3, always staying behind the first-base bag while keeping a 2–3 step halo around F3 and a view of his shoe tops","Move inside the diamond to compensate","Switch places with U2"]'::jsonb, 1, 'On the big diamond U1 (and U3) always set up behind the bag, adjusting depth with the fielder — never crowding inside the 2–3 step halo, never so deep they lose the shoe tops needed to rule on a sinking line drive.', 'published'),
  ('mech-087', 'mechBig', 'Positioning', 'big', 'Big diamond, runner on first, pickoff-happy pitcher. May U1 angle himself for the pickoff throw before the pitch?', '["No — square to the plate at all times","Yes — U1 may initially set an angle for the pickoff at first, but must be square to the plate by the time the pitch is delivered, shortening up to use the wedge on a throw over","Yes, and he may stay angled through the pitch","Only with two outs"]'::jsonb, 1, 'U1 can cheat his angle early for the pickoff, but the position of record at pitch delivery is square to the plate in foul territory, right foot near the line — shortened up enough to find the wedge on a play back into first.', 'published'),
  ('mech-088', 'mechBig', 'Positioning', 'big', 'Big diamond, nobody on. A routine ground ball goes to F6. What does the plate umpire do while the throw goes across?', '["Hold the plate area no matter what","Clear the catcher to the left and trail the batter-runner up the line, observing the play at first and offering U1 information if asked, then return to PoP","Rotate toward third for the next play","Follow the ball to shortstop"]'::jsonb, 1, 'With nobody on, PU clears the catcher and trails the batter-runner, backing up the play at first (pulled foot, swipe tag, lane violation) before returning to PoP. Note the exception: with R3 only, PU stays home instead of trailing.', 'published'),
  ('mech-089', 'mechBig', 'Positioning', 'big', 'Big diamond, runner on first, ground ball in the hole to F6 with a force coming to second. As the 2026 point of emphasis directs, how does U2 work this from the deep “B only” spot?', '["Sprint to the bag and straddle it","Step up to stay chest to ball and step toward the throw for the angle, get set — never moving at the moment of the force — with eyes to the base, then drift with eyes down on runner and fielder","Back out of the infield for a wide view","Freeze in place and lean"]'::jsonb, 1, 'The double-play footwork emphasis for inside U2: step up from deep B, step toward the throw for the angle, and be absolutely set with eyes on the base when the force happens. Drifting with eyes down afterward catches slide infractions and the exchange.', 'published'),
  ('mech-090', 'mechBig', 'Infield Coverage', 'big', 'Big diamond, runners on first and second (U2 inside). A routine humpback pop-up settles over the middle infield. Who has catch/no-catch?', '["PU, as on the 60-ft diamond","U2 — when he is positioned inside, all routine infield catch/no-catch belongs to him","U1 and U3 split it at second base","The nearest fielder’s umpire by open glove"]'::jsonb, 1, 'When U2 is inside the diamond, he takes all routine infield catch/no-catch. With nobody on or R3 only (U2 outside), those routine infield flies belong to the plate umpire instead.', 'published'),
  ('mech-091', 'mechBig', 'Infield Coverage', 'big', 'Big diamond. A soft liner forces F4 to dive to his right, gloving the ball inches off the grass. Nobody on base. Who rules catch or trap?', '["U1 — F4 belongs to him in every direction","U2 — a ball hit directly at F4 or F6, F4 diving right, or F6 diving left is U2’s","PU — every infield liner is his","U3 — the ball is moving toward his side"]'::jsonb, 1, 'The infield split: U1 has balls straight at F3 and anything taking F3 or F4 to their left; U2 has balls straight at F4 or F6, F4 diving right, and F6 diving left; U3 has balls straight at F5 and anything taking F5 or F6 to their right; PU has the pitcher and chargers on the grass.', 'published'),
  ('mech-092', 'mechBig', 'Infield Coverage', 'big', 'Big diamond. F5 charges hard on a swinging bunt and short-hops-or-catches it on the infield grass near the mound-side. Who has the catch/no-catch?', '["U3, since it is F5","The plate umpire — any ball to the pitcher or to an infielder charging in on the infield grass is his","U2, closest to the grass","U1, on the throw side"]'::jsonb, 1, 'Fielders charging in on the grass — and anything the pitcher plays — belong to the plate umpire, who has the head-on look at a scoop versus a short hop. The base umpires’ open-glove reads cover the balls hit at or beside their fielders.', 'published'),
  ('mech-093', 'mechBig', 'Infield Coverage', 'big', 'Big diamond. A low screamer takes F6 ranging to his right, backhand, glove opening toward third base. Who rules on the short-hop?', '["U2 — F6 is always his","U3 — a ball taking F5 or F6 to his right belongs to U3, matching the open glove","U1 across the diamond","PU by default"]'::jsonb, 1, 'F6 moving right means the glove opens toward third — U3’s call, per both the assignment table and the open glove theory it encodes. F6 diving left would flip it to U2.', 'published'),
  ('mech-094', 'mechBig', 'Infield Coverage', 'big', 'Big diamond. Why must U1, U2, and U3 be able to see the shoe tops of the fielder in front of them from their starting positions?', '["To judge the fielder’s foot speed","So they can rule catch versus trap on a sinking line drive played below the fielder’s waist — the open-glove calls that belong to them","To check the fielder’s footwear for metal cleats","It is a tradition with no practical purpose"]'::jsonb, 1, 'Balls played below the waist are the base umpires’ calls under the open glove theory, and the difference between a catch and a short hop lives at the fielder’s shoe tops. Set up too deep or too shielded and that call is a guess.', 'published'),
  ('mech-095', 'mechBig', 'Infield Coverage', 'big', 'Big diamond, runner on third breaking on contact. A slow roller hugs the third-base line between home and third, and R3’s dash home screens the plate umpire. Who bails the crew out on fair/foul, and what is the situation called?', '["U3 takes the call — the “pinch,” pre-signaled whenever R3 is aboard","U2 from the middle — the “squeeze”","U1 from across the field — the “cross”","The call is suspended until the runner passes"]'::jsonb, 0, 'Same pinch mechanic as the small field: with R3, the runner can block the plate umpire’s view of a ball between home and third, so fair/foul passes to U3. Crews signal the pinch pre-pitch whenever R3 is on.', 'published'),
  ('mech-096', 'mechBig', 'Tag-Ups & Touches', 'big', 'Big diamond crews state their tag-up philosophy differently than 60-ft crews. What is the big-diamond rule for retouch responsibility when the crew rotates?', '["Retouches always go to the plate umpire","Retouch responsibility never reverts to an umpire behind the runner — coverage stays in front","Each umpire keeps his original base’s retouch from wherever he is","Retouches are shared calls requiring two umpires"]'::jsonb, 1, 'The governing principle on the big diamond: tag-up responsibility will not revert to an umpire positioned behind that runner. The rotations are built so someone ahead of each runner owns the retouch — like PU taking R3’s tag-up in the Reverse rotation.', 'published'),
  ('mech-097', 'mechBig', 'Tag-Ups & Touches', 'big', 'Big diamond, runners on first and second, routine single to right — no umpire goes out. Who watches R2’s retouch-or-advance and R1’s retouch on this routine base hit?', '["U1 has R1’s retouch and the BR’s touch of first; U2 has R2 and everything at second; U3 waits at Po3","PU takes all retouches from the plate","U3 has both retouches from third","Retouches do not apply on base hits"]'::jsonb, 0, 'When nobody rotates out, each umpire keeps his own base: U1 watches R1’s retouch and the batter-runner touching first, U2 owns second including R2’s retouch, U3 holds third, and PU stays at PoP for the plate.', 'published'),
  ('mech-098', 'mechBig', 'Tag-Ups & Touches', 'big', 'Big diamond, Full rotation (nobody on, U2 out, ball in the gap). The batter-runner motors around the bases. Who has his touch at each base?', '["U1 at first and then home after releasing; U3 at second; PU at third","PU at first; U1 at second; U3 at third and home","U3 everywhere until the ball comes in","U1 at first, second, and third"]'::jsonb, 0, 'Full-rotation touch map on the big diamond mirrors the small field: U1 has the BR at first and, after releasing when the runner reaches second, at home; the remaining middle umpire covers second; the plate umpire covers third.', 'published'),
  ('mech-099', 'mechBig', 'Tag-Ups & Touches', 'big', 'Big diamond, Reverse rotation touch map. U3 went out with runners in scoring position. Who owns the touches at second and third as the runners advance?', '["U1 owns everything in the middle","U2 — sliding with the lead runner, he has the lead runners at second and the trail coverage at third; U1 has the batter-runner at first and second; PU has home","PU covers second and third at once","U3 keeps them from the outfield"]'::jsonb, 1, 'In the Reverse (slide) rotation: PU has all runners at home, U1 has the batter-runner at first and second, and the sliding middle umpire (U2 when U3 goes out) has the lead runners at second and the plays at third.', 'published'),
  ('mech-100', 'mechBig', 'Tag-Ups & Touches', 'big', 'Big diamond, U2 Drift in progress (U1 went out with a runner on first). The batter-runner rounds first wide while R1 holds at second. Two bases, one umpire. How does U2 handle owning both first and second at once?', '["Pick the base closest to the ball and ignore the other","Work with depth in the working area, stay chest to ball, and let the ball take him to the play — never overcommitting to one base until responsibilities become singular","Straddle a midpoint and never move","Call for help from U3"]'::jsonb, 1, 'Multiple-base coverage is worked from the working area with depth: chest to ball, reading the throw, letting the ball dictate which base becomes the play. Overcommitting early to one base is what leaves the other one uncovered.', 'published')
